  ('BESI-BIRU-0.45x121','Besi Biru','0.45x121',0.75,6,'m',15,0.4,'seed'),
  ('BESI-BIRU-0.73x153','Besi Biru','0.73x153',1.55,6,'m',25,0.4,'seed')
on conflict (code) do nothing;

-- ─── 7 · ROW-LEVEL SECURITY ─────────────────────────────────────────────────
alter table hrd_materials       enable row level security;
alter table hrd_quotes          enable row level security;
alter table hrd_supplier_prices enable row level security;
alter table hrd_price_history   enable row level security;
alter table hrd_config          enable row level security;

do $$
declare t text;
begin
  foreach t in array array['hrd_materials','hrd_quotes','hrd_supplier_prices','hrd_price_history','hrd_config'] loop
    execute format('drop policy if exists %I_rw on %I', t, t);
    execute format('create policy %I_rw on %I for all to authenticated using (is_allowed()) with check (is_allowed())', t, t);
  end loop;
end $$;

-- ─── 8 · HELPERS ────────────────────────────────────────────────────────────
create or replace function hrd_cfg(p_key text) returns text
language sql stable security definer set search_path = public as $$
  select value from hrd_config where key = p_key;
$$;

-- clientRate = (costPrice / barQty when barQty≠0 else costPrice) × (1 + markup)
-- (exact port of withRates_ in Code.gs; missing material → rate 0)
create or replace function hrd_client_rate(p_code text) returns double precision
language sql stable security definer set search_path = public as $$
  select coalesce((
    select (case when coalesce(bar_qty,0) <> 0 then cost_price / bar_qty else cost_price end)
           * (1 + coalesce(markup,0))
    from hrd_materials where code = p_code
  )::double precision, 0);
$$;

create or replace function hrd_unit_of(p_code text) returns text
language sql stable security definer set search_path = public as $$
  select coalesce((select unit from hrd_materials where code = p_code), '');
$$;

-- roundUp_(x) = Math.ceil(x - 1e-9)  — exact port
create or replace function hrd_roundup(x double precision) returns double precision
language sql immutable as $$ select ceil(x - 1e-9); $$;

-- one costing line { item, code, rate, sub, qty, unit, total: sub*qty }
create or replace function hrd_line(p_item text, p_code text, p_rate double precision,
  p_sub double precision, p_qty double precision, p_unit text) returns jsonb
language sql immutable as $$
  select jsonb_build_object('item',p_item,'code',p_code,'rate',p_rate,'sub',p_sub,
                            'qty',p_qty,'unit',p_unit,'total',p_sub*p_qty);
$$;

-- ─── 9 · SAVE QUOTE RPC — authoritative server-side recompute ────────────────
-- Exact port of computeQuote_ + saveQuote in Code.gs. Rates are resolved from
-- the LIVE hrd_materials catalog and the full snapshot (inputs, lines, metrics)
-- is frozen into hrd_quotes.data — editing material prices later never changes
-- a saved quote.
-- VERIFIED TEST CASE (Excel port): inputs L=160, H=2.4, CC=3, doors=1,
-- horizLines=3, footPerPost=2, pInstall=8, pFab=15, gateDays=2, sqftF=11.16,
-- gStruct=40.8, gPanel=155, gPosts=2, gFoot=4, oXbrace=0, post=MS-50x75x1.5,
-- horiz=MS-50x50x1.5, panel=DECK-0.23, footing=FOOTING-450x450x750, seed rates
-- → hoarding_total 47,860.14 · gate_total 5,740.26 · subtotal 53,600.39.
-- payload: { id?, quoteNo?, date?, client, contact, project, mall, lot,
--            location, validity, status, inputs:{...builder form...} }
create or replace function hrd_save_quote(payload jsonb) returns jsonb
language plpgsql security definer set search_path = public as $$
declare
  i jsonb := coalesce(payload->'inputs', '{}'::jsonb);
  -- inputs (double precision = IEEE-754 doubles, same maths as the JS/Excel engine)
  v_length double precision := coalesce(nullif(i->>'length','')::double precision, 0);
  v_height double precision := coalesce(nullif(i->>'height','')::double precision, 0);
  v_cc     double precision;
  v_doors  double precision := coalesce(nullif(i->>'doors','')::double precision, 0);
  v_horiz_lines   double precision := coalesce(nullif(i->>'horizLines','')::double precision, 0);
  v_foot_per_post double precision := coalesce(nullif(i->>'footPerPost','')::double precision, 0);
  v_p_install double precision;
  v_p_fab     double precision;
  v_gate_days double precision := coalesce(nullif(i->>'gateDays','')::double precision, 0);
  v_sqft_f   double precision := coalesce(nullif(i->>'sqftF','')::double precision, 0);
  v_g_struct double precision := coalesce(nullif(i->>'gStruct','')::double precision, 0);
  v_g_panel  double precision := coalesce(nullif(i->>'gPanel','')::double precision, 0);
  v_g_posts  double precision := coalesce(nullif(i->>'gPosts','')::double precision, 0);
  v_g_foot   double precision := coalesce(nullif(i->>'gFoot','')::double precision, 0);
  v_o_xbrace double precision := coalesce(nullif(i->>'oXbrace','')::double precision, 0);
  v_xbrace_len double precision;
  v_l_fab_post double precision := coalesce(nullif(i->>'lFabPost','')::double precision, 0);
  v_l_prelim   double precision := coalesce(nullif(i->>'lPrelim','')::double precision, 0);
  v_l_install  double precision := coalesce(nullif(i->>'lInstall','')::double precision, 0);
  v_l_fab_gate double precision := coalesce(nullif(i->>'lFabGate','')::double precision, 0);
  v_l_install_gate double precision := coalesce(nullif(i->>'lInstallGate','')::double precision, 0);
  v_sst_pct double precision := coalesce(nullif(i->>'sst','')::double precision, 0);
  -- category-driven material selection (backward compatible with old
  -- cladding/fixed-code quotes, same fallback chain as Code.gs)
  v_post_code  text := coalesce(i->>'postCode','');
  v_horiz_code text := coalesce(i->>'horizCode','');
  v_panel_code text;
  v_found_code text;
  v_deck_gate  text;
  v_xbrace_code text;
  -- derived
  post_per_post double precision;
  posts double precision; install_days double precision; fab_days double precision;
  deck_sqft double precision;
  r_post double precision; r_horiz double precision;
  "H" jsonb := '[]'::jsonb; "G" jsonb := '[]'::jsonb;
  hoard_total double precision; gate_total double precision;
  v_sub double precision; v_sst_amt double precision; v_grand double precision;
  v_metrics jsonb; v_data jsonb;
  -- record plumbing
  v_id uuid; v_existing hrd_quotes%rowtype; v_found boolean := false;
  v_quoteno text; v_status text; v_date date;
  v_prefix text; v_year text := to_char(now() at time zone 'Asia/Kuala_Lumpur','YYYY');
  v_seq int; v_cur int; v_used int; v_m text;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  if coalesce(payload->>'client','') = '' then raise exception 'Client name is required.'; end if;

  -- n(i.cc)||1 / n(i.pInstall)||1 / n(i.pFab)||1
  v_cc := coalesce(nullif(i->>'cc','')::double precision, 0);
  if v_cc = 0 then v_cc := 1; end if;
  v_p_install := coalesce(nullif(i->>'pInstall','')::double precision, 0);
  if v_p_install = 0 then v_p_install := 1; end if;
  v_p_fab := coalesce(nullif(i->>'pFab','')::double precision, 0);
  if v_p_fab = 0 then v_p_fab := 1; end if;

  v_xbrace_len := coalesce(nullif(i->>'xbraceLen','')::double precision,
                           coalesce(nullif(hrd_cfg('XBRACE_LEN'),'')::double precision, 10.8));

  v_panel_code := coalesce(nullif(i->>'panelCode',''),
    case when i->>'cladding' = 'gi'
         then coalesce(nullif(i->>'giCode',''), hrd_cfg('CODE_GI'))
         else coalesce(nullif(i->>'deckMain',''), hrd_cfg('CODE_DECK_MAIN')) end);
  v_found_code  := coalesce(nullif(i->>'foundCode',''), nullif(i->>'footCode',''), hrd_cfg('CODE_FOOTING'));
  v_deck_gate   := coalesce(nullif(i->>'deckGate',''), hrd_cfg('CODE_DECK_GATE'));
  v_xbrace_code := coalesce(nullif(i->>'xbraceCode',''), hrd_cfg('CODE_XBRACE'));

  -- ═══ CALC ENGINE (do not change — exact Excel port) ═══
  post_per_post := 2 * sqrt(power(v_height - 0.3, 2) + power(1.2, 2)) + 2.1;
  posts        := hrd_roundup(v_length / v_cc);
  install_days := hrd_roundup(posts / v_p_install);
  fab_days     := hrd_roundup(posts / v_p_fab);
  deck_sqft    := hrd_roundup(v_length * v_height * v_sqft_f);
  r_post  := hrd_client_rate(v_post_code);
  r_horiz := hrd_client_rate(v_horiz_code);

  "H" := "H" || hrd_line('Vertical Post + Brace', v_post_code, r_post, post_per_post * r_post, posts, 'set');
  "H" := "H" || hrd_line('Horizontal', v_horiz_code, r_horiz, r_horiz, v_length * v_horiz_lines, 'm');
  "H" := "H" || hrd_line('Labor Fabrication (Post)', '—', v_l_fab_post, v_l_fab_post, posts, 'set');
  "H" := "H" || hrd_line('Preliminaries', '—', v_l_prelim, v_l_prelim, install_days, 'day');
  "H" := "H" || hrd_line('Labor Installation (Onsite)', '—', v_l_install, v_l_install, install_days, 'day');
  "H" := "H" || hrd_line('Hoarding Panel', v_panel_code, hrd_client_rate(v_panel_code), hrd_client_rate(v_panel_code), deck_sqft, hrd_unit_of(v_panel_code));
  "H" := "H" || hrd_line('Base / Footing', v_found_code, hrd_client_rate(v_found_code), hrd_client_rate(v_found_code), posts * v_foot_per_post, hrd_unit_of(v_found_code));
  "H" := "H" || hrd_line('ADD ON: X Brace', v_xbrace_code, hrd_client_rate(v_xbrace_code), v_xbrace_len * hrd_client_rate(v_xbrace_code), v_o_xbrace, 'set');
  select coalesce(sum((e->>'total')::double precision), 0) into hoard_total from jsonb_array_elements("H") e;

  "G" := "G" || hrd_line('Gate Post', v_post_code, r_post, post_per_post * r_post, v_doors * v_g_posts, 'nos');
  "G" := "G" || hrd_line('Gate Structure', v_horiz_code, r_horiz, r_horiz, v_doors * v_g_struct, 'm');
  "G" := "G" || hrd_line('Gate Panel', v_deck_gate, hrd_client_rate(v_deck_gate), hrd_client_rate(v_deck_gate), v_doors * v_g_panel, hrd_unit_of(v_deck_gate));
  "G" := "G" || hrd_line('Base / Footing (Gate)', v_found_code, hrd_client_rate(v_found_code), hrd_client_rate(v_found_code), v_doors * v_g_foot, hrd_unit_of(v_found_code));
  "G" := "G" || hrd_line('Labor Fabrication (Post-Gate)', '—', v_l_fab_post, v_l_fab_post, v_doors * v_g_posts, 'nos');
  "G" := "G" || hrd_line('Labor Fabrication (Gate)', '—', v_l_fab_gate, v_l_fab_gate, v_doors, 'nos');
  "G" := "G" || hrd_line('Labor Installation (Gate Onsite)', '—', v_l_install_gate, v_l_install_gate, v_doors * v_gate_days, 'day');
  select coalesce(sum((e->>'total')::double precision), 0) into gate_total from jsonb_array_elements("G") e;

  v_sub     := hoard_total + gate_total;
  v_sst_amt := v_sub * (v_sst_pct / 100);
  v_grand   := v_sub + v_sst_amt;
  -- ═══ end calc engine ═══

  v_metrics := jsonb_build_object(
    'posts', posts, 'postPerPost', post_per_post, 'vert', posts * post_per_post,
    'horiz', v_length * v_horiz_lines, 'foot', posts * v_foot_per_post,
    'sqft', deck_sqft, 'installDays', install_days, 'fabDays', fab_days,
    'projectDays', greatest(install_days, fab_days) + v_doors * v_gate_days);
  v_data := jsonb_build_object('inputs', i, 'lines', jsonb_build_object('H', "H", 'G', "G"), 'metrics', v_metrics);

  v_status := case when payload->>'status' in ('Draft','Sent','Won','Lost')
                   then payload->>'status' else 'Draft' end;
  v_date := coalesce(nullif(payload->>'date','')::date,
                     (now() at time zone 'Asia/Kuala_Lumpur')::date);

  -- existing record?
  if coalesce(payload->>'id','') <> '' then
    select * into v_existing from hrd_quotes where id = (payload->>'id')::uuid;
    if not found then raise exception 'Quote not found.'; end if;
    v_found := true;
  end if;

  -- quote number: given > existing > next sequential PREFIX-YYYY-### (skips used)
  v_quoteno := nullif(payload->>'quoteNo','');
  if v_quoteno is null and v_found then v_quoteno := v_existing.quote_no; end if;
  if v_quoteno is null then
    v_prefix := coalesce(nullif(hrd_cfg('QUOTE_PREFIX'),''), 'HG-Q-');
    v_seq := coalesce(nullif(hrd_cfg('QUOTE_SEQ'),'')::int, 0);
    loop
      v_seq := v_seq + 1;
      v_quoteno := v_prefix || v_year || '-' || lpad(v_seq::text, 3, '0');
      exit when not exists (select 1 from hrd_quotes where lower(quote_no) = lower(v_quoteno));
    end loop;
  end if;

  if v_found then
    update hrd_quotes set
      quote_no = v_quoteno, quote_date = v_date,
      client = payload->>'client', contact = coalesce(payload->>'contact',''),
      project = coalesce(payload->>'project',''), mall = coalesce(payload->>'mall',''),
      lot = coalesce(payload->>'lot',''), location = coalesce(payload->>'location',''),
      validity = coalesce(nullif(payload->>'validity','')::numeric, 0), status = v_status,
      length = round(v_length::numeric, 4), height = round(v_height::numeric, 4), doors = round(v_doors::numeric, 4),
      hoarding_total = round(hoard_total::numeric, 2), gate_total = round(gate_total::numeric, 2),
      subtotal = round(v_sub::numeric, 2), sst_pct = round(v_sst_pct::numeric, 4),
      sst_amount = round(v_sst_amt::numeric, 2), grand_total = round(v_grand::numeric, 2),
      data = v_data, updated_by = current_email(), updated_at = now()
    where id = v_existing.id
    returning id into v_id;
    perform log_audit('HRD UPDATE Quote',
      v_quoteno || ' · ' || (payload->>'client') || ' / RM ' || to_char(round(v_grand::numeric,2), 'FM999,999,999,990.00'));
  else
    insert into hrd_quotes (quote_no, quote_date, client, contact, project, mall, lot, location,
      validity, status, length, height, doors, hoarding_total, gate_total, subtotal,
      sst_pct, sst_amount, grand_total, data, created_by, updated_by)
    values (v_quoteno, v_date, payload->>'client', coalesce(payload->>'contact',''),
      coalesce(payload->>'project',''), coalesce(payload->>'mall',''),
      coalesce(payload->>'lot',''), coalesce(payload->>'location',''),
      coalesce(nullif(payload->>'validity','')::numeric, 0), v_status,
      round(v_length::numeric,4), round(v_height::numeric,4), round(v_doors::numeric,4),
      round(hoard_total::numeric,2), round(gate_total::numeric,2), round(v_sub::numeric,2),
      round(v_sst_pct::numeric,4), round(v_sst_amt::numeric,2), round(v_grand::numeric,2),
      v_data, current_email(), current_email())
    returning id into v_id;
    -- bumpQuoteSeq_: trailing digits of the number used, if > stored QUOTE_SEQ
    v_m := substring(v_quoteno from '(\d+)\s*$');
    if v_m is not null then
      v_cur := coalesce(nullif(hrd_cfg('QUOTE_SEQ'),'')::int, 0);
      v_used := v_m::int;
      if v_used > v_cur then
        insert into hrd_config (key, value) values ('QUOTE_SEQ', v_used::text)
        on conflict (key) do update set value = excluded.value;
      end if;
    end if;
    perform log_audit('HRD CREATE Quote',
      v_quoteno || ' · ' || (payload->>'client') || ' / RM ' || to_char(round(v_grand::numeric,2), 'FM999,999,999,990.00'));
  end if;

  return jsonb_build_object('id', v_id, 'quote_no', v_quoteno);
end;
$$;

-- ─── 10 · MATERIAL PRICE EDIT RPC (atomic: update + history + audit) ─────────
create or replace function hrd_edit_material_price(p_code text, p_field text, p_value numeric, p_reason text)
returns void
language plpgsql security definer set search_path = public as $$
declare
  v_old numeric; v_new numeric;
  v_old_disp numeric; v_new_disp numeric; v_field_disp text;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  if p_field not in ('costPrice','markup') then raise exception 'Bad field.'; end if;
  v_new := coalesce(p_value, 0);
  if p_field = 'markup' then v_new := v_new / 100; end if;  -- form sends % (40), store fraction (0.4)
  select case when p_field = 'markup' then coalesce(markup,0) else coalesce(cost_price,0) end
    into v_old from hrd_materials where code = p_code;
  if not found then raise exception 'Material not found.'; end if;
  if abs(v_old - v_new) < 1e-9 then return; end if;
  if p_field = 'markup' then
    update hrd_materials set markup = v_new, updated_at = now(), updated_by = current_email() where code = p_code;
    v_old_disp := v_old * 100; v_new_disp := v_new * 100; v_field_disp := 'Markup %';
  else
    update hrd_materials set cost_price = v_new, updated_at = now(), updated_by = current_email() where code = p_code;
    v_old_disp := v_old; v_new_disp := v_new; v_field_disp := 'Cost Price';
  end if;
  insert into hrd_price_history (code, field, old_val, new_val, user_email, reason)
  values (p_code, v_field_disp, v_old_disp, v_new_disp, current_email(), coalesce(p_reason,''));
  perform log_audit('HRD PRICE-CHANGE Material',
    p_code || ' · ' ||
    case when p_field = 'markup' then v_old_disp || '% -> ' || v_new_disp || '%'
         else 'RM' || v_old_disp || ' -> RM' || v_new_disp end ||
    case when coalesce(p_reason,'') <> '' then ' (' || p_reason || ')' else '' end);
end;
$$;

-- ─── 11 · APPLY SUPPLIER PRICE → CATALOG RPC (logs a price change too) ───────
create or replace function hrd_apply_supplier(p_id uuid) returns void
language plpgsql security definer set search_path = public as $$
declare
  s hrd_supplier_prices%rowtype;
  v_old numeric;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  select * into s from hrd_supplier_prices where id = p_id;
  if not found then raise exception 'Supplier price not found.'; end if;
  select coalesce(cost_price,0) into v_old from hrd_materials where code = s.code;
  if not found then raise exception 'Material % not in catalog.', s.code; end if;
  update hrd_materials set cost_price = s.cost_price, updated_at = now(), updated_by = current_email()
  where code = s.code;
  insert into hrd_price_history (code, field, old_val, new_val, user_email, reason)
  values (s.code, 'Cost Price', v_old, s.cost_price, current_email(), 'Applied supplier: ' || s.supplier);
  perform log_audit('HRD PRICE-CHANGE Material',
    s.code || ' · RM' || v_old || ' -> RM' || s.cost_price || ' (supplier ' || s.supplier || ')');
end;
$$;

-- Done. No storage bucket (the GAS app stores no files) and no hrd_alarms view
-- (the GAS app has no scheduled email digests).

-- ========== MODULE: schema-visual ==========
-- ============================================================================
-- HG GROUP — VISUAL WORKS CONTROL · Supabase schema (slug: visual, prefix: vis_)
-- Converted from apps-script-visual (Black Lee — Visual Works, GAS + Sheets).
-- Run AFTER the foundation schema.sql. Additive + idempotent — safe to re-run.
--
-- Uses from the foundation (never redefined here):
--   allowed_users, is_allowed(), is_admin(), current_email(), log_audit(), app_settings
--
-- Creates:
--   vis_malls, vis_materials, vis_rates, vis_jobs, vis_job_panels,
--   vis_permits, vis_workers, vis_invoices, vis_invoice_jobs
--   vis_pick_rate() helper · vis_save_job() RPC · vis_save_invoice() RPC
--   vis_alarms view (permit + worker-doc expiry — feeds daily-alarms edge fn)
--   storage bucket 'visual' (sketches, proofs, photos, permits, worker docs, B invoices)
-- ============================================================================

-- ─── MASTERS ────────────────────────────────────────────────────────────────
create table if not exists vis_malls (
  id         uuid primary key default gen_random_uuid(),
  name       text not null unique,
  notes      text default '',
  updated_at timestamptz default now()
);

create table if not exists vis_materials (
  id         uuid primary key default gen_random_uuid(),
  name       text not null unique,
  notes      text default '',
  updated_at timestamptz default now()
);

-- Seed materials (same as GAS setupConfig → seedMaterials_)
insert into vis_materials (name) values
  ('Tarpaulin'), ('Sticker'), ('Fabric'), ('Vinyl'), ('Forex Board')
on conflict (name) do nothing;

-- ─── RATE CARD — B's rates per mall / material / job type ───────────────────
create table if not exists vis_rates (
  id             uuid primary key default gen_random_uuid(),
  mall           text default 'ALL',
  material       text default 'ALL',
  job_type       text default 'ALL',          -- print_install / print_only / install_only / ALL
  rate_per_sqft  numeric default 0,           -- print rate
  install_rate   numeric default 0,
  package_rate   numeric default 0,           -- all-in supply+install (overrides split)
  min_charge     numeric default 0,
  effective_from date,
  notes          text default '',
  updated_by     text default '',
  updated_at     timestamptz default now()
);

-- ─── JOBS + PANELS ──────────────────────────────────────────────────────────
create table if not exists vis_permits (
  id          uuid primary key default gen_random_uuid(),
  mall        text not null,
  lot_no      text default '',
  permit_type text default '',                -- monthly / yearly / one-off
  permit_no   text default '',
  valid_from  date,
  valid_to    date,
  file_url    text default '',                -- pasted link (if any)
  file_path   text default '',                -- storage path in bucket 'visual'
  notes       text default '',
  created_by  text default '',
  created_at  timestamptz default now()
);

create table if not exists vis_jobs (
  id                 uuid primary key default gen_random_uuid(),
  job_no             text not null unique,    -- VIS-YYYY-####
  status             text not null default 'NEW',
  mall               text not null,
  lot_no             text not null,
  job_type           text not null default 'print_install',
  client             text default '',
  requested_by       text default '',
  request_date       date,
  install_date       date,
  completed_date     date,
  artwork_link       text default '',         -- WeTransfer / Drive link (URL kept as-is)
  artwork_proof_url  text default '',         -- pasted proof link
  artwork_proof_path text default '',         -- uploaded proof (storage path)
  sketch_url         text default '',         -- pasted sketch link
  sketch_path        text default '',         -- uploaded sketch (storage path)
  site_photo_paths   jsonb default '[]'::jsonb,  -- site reference photos (storage paths)
  photo_paths        jsonb default '[]'::jsonb,  -- completion photos (storage paths)
  material           text default '',
  total_sqft         numeric default 0,
  rate_id            uuid,
  rate_per_sqft      numeric default 0,
  install_rate       numeric default 0,
  subtotal           numeric default 0,
  expected_amount    numeric default 0,
  permit_id          uuid references vis_permits(id) on delete set null,
  proceed_by         text default '',
  proceed_at         timestamptz,
  notes              text default '',
  created_by         text default '',
  created_at         timestamptz default now(),
  updated_at         timestamptz default now()
);
create index if not exists idx_vis_jobs_status on vis_jobs (status);
create index if not exists idx_vis_jobs_mall   on vis_jobs (mall);

create table if not exists vis_job_panels (
  id            uuid primary key default gen_random_uuid(),
  job_id        uuid not null references vis_jobs(id) on delete cascade,
  label         text default '',
  width_val     numeric default 0,
  height_val    numeric default 0,
  unit          text default 'mm',            -- mm / cm / m / in / ft
  qty           numeric default 1,
  sqft          numeric default 0,
  material      text default '',
  rate_per_sqft numeric default 0,
  amount        numeric default 0
);
create index if not exists idx_vis_panels_job on vis_job_panels (job_id);

-- ─── B's WORKERS (IC / CIDB / WAH / other doc slots) ────────────────────────
create table if not exists vis_workers (
  id             uuid primary key default gen_random_uuid(),
  name           text not null,
  role           text default '',
  phone          text default '',
  ic_no          text default '',
  ic_file_url    text default '',
  ic_file_path   text default '',
  cidb_no        text default '',
  cidb_expiry    date,
  cidb_file_url  text default '',
  cidb_file_path text default '',
  wah_no         text default '',
  wah_expiry     date,
  wah_file_url   text default '',
  wah_file_path  text default '',
  doc_type       text default '',
  doc_no         text default '',
  doc_expiry     date,
  doc_url        text default '',
  doc_file_path  text default '',
  status         text default 'active',       -- active / inactive
  notes          text default '',
  updated_by     text default '',
  updated_at     timestamptz default now()
);

-- ─── B's INVOICES + RECONCILIATION ──────────────────────────────────────────
create table if not exists vis_invoices (
  id             uuid primary key default gen_random_uuid(),
  inv_no         text not null,
  inv_date       date,
  period         text default '',
  malls          text default '',
  claimed_amount numeric default 0,
  sst_enabled    boolean default false,
  sst_amount     numeric default 0,
  claimed_total  numeric default 0,
  file_url       text default '',
  file_path      text default '',
  status         text default 'checking',     -- checking / verified / disputed / paid
  recon_verdict  text default '',             -- MATCH / CHECK
  recon_note     text default '',
  notes          text default '',
  created_by     text default '',
  created_at     timestamptz default now(),
  updated_at     timestamptz default now()
);

-- job_id intentionally NOT a foreign key: like the GAS original, deleting a job
-- keeps the invoice line (shown as "(deleted)").
create table if not exists vis_invoice_jobs (
  id              uuid primary key default gen_random_uuid(),
  invoice_id      uuid not null references vis_invoices(id) on delete cascade,
  job_id          uuid not null,
  claimed_sqft    numeric default 0,
  claimed_amount  numeric default 0,
  recorded_sqft   numeric default 0,
  recorded_amount numeric default 0,
  variance_rm     numeric default 0,
  flag            text default ''              -- OK / OVER / UNDER
);
create index if not exists idx_vis_invjobs_inv on vis_invoice_jobs (invoice_id);

-- ─── ROW-LEVEL SECURITY — allowlist-gated everything ────────────────────────
do $$
declare t text;
begin
  foreach t in array array['vis_malls','vis_materials','vis_rates','vis_jobs',
    'vis_job_panels','vis_permits','vis_workers','vis_invoices','vis_invoice_jobs'] loop
    execute format('alter table %I enable row level security', t);
    execute format('drop policy if exists %I_rw on %I', t, t);
    execute format('create policy %I_rw on %I for all to authenticated using (is_allowed()) with check (is_allowed())', t, t);
  end loop;
end $$;

-- ─── STORAGE — bucket for sketches / proofs / photos / permits / docs / invoices
insert into storage.buckets (id, name, public) values ('visual','visual', false)
on conflict (id) do nothing;
drop policy if exists "visual_rw" on storage.objects;
create policy "visual_rw" on storage.objects for all to authenticated
  using (bucket_id = 'visual' and is_allowed())
  with check (bucket_id = 'visual' and is_allowed());

-- ─── RATE PICKER — most-specific match wins ─────────────────────────────────
-- mall+material+jobType (7) > mall+material (6) > mall+jobType (5) > mall (4)
-- > material(+type) (2-3) > jobType (1) > ALL (0). Only rates effective on/before
-- the job date count; tie-break = most recent effective_from. NULL if no match.
create or replace function vis_pick_rate(p_mall text, p_material text, p_job_type text, p_date date)
returns vis_rates
language plpgsql stable security definer set search_path = public as $$
declare
  r vis_rates;
begin
  select * into r
  from vis_rates v
  where (v.effective_from is null or p_date is null or v.effective_from <= p_date)
    and (lower(coalesce(v.mall,''))     in ('','all','any','*') or lower(v.mall)     = lower(coalesce(p_mall,'')))
    and (lower(coalesce(v.material,'')) in ('','all','any','*') or lower(v.material) = lower(coalesce(p_material,'')))
    and (lower(coalesce(v.job_type,'')) in ('','all','any','*') or lower(v.job_type) = lower(coalesce(p_job_type,'')))
  order by
    ( (case when lower(coalesce(v.mall,''))     not in ('','all','any','*') then 4 else 0 end)
    + (case when lower(coalesce(v.material,'')) not in ('','all','any','*') then 2 else 0 end)
    + (case when lower(coalesce(v.job_type,'')) not in ('','all','any','*') then 1 else 0 end) ) desc,
    v.effective_from desc nulls last
  limit 1;
  return r;   -- null record when nothing matches
end;
$$;

-- ─── SAVE JOB RPC — server recomputes every sqft + amount (never trusts client)
-- payload: { id?, status?, mall, lotNo, jobType, client, requestedBy, requestDate,
--            installDate, material, notes, permitId, artworkLink,
--            sketchPath?, sketchLink?, proofPath?, proofLink?, sitePhotoPaths?[],
--            panels:[{label,widthVal,heightVal,unit,qty,material?,ratePerSqft?}] }
create or replace function vis_save_job(payload jsonb) returns jsonb
language plpgsql security definer set search_path = public as $$
declare
  v_editing   boolean := coalesce(payload->>'id','') <> '';
  v_id        uuid;
  v_old       vis_jobs;
  v_job_no    text;
  v_year      text := to_char(now() at time zone 'Asia/Kuala_Lumpur', 'YYYY');
  v_next      int;
  v_mall      text := trim(coalesce(payload->>'mall',''));
  v_lot       text := trim(coalesce(payload->>'lotNo',''));
  v_type      text;
  v_date      date;
  v_material  text := trim(coalesce(payload->>'material',''));
  v_rate      vis_rates;           -- job-level rate snapshot
  v_prate     vis_rates;           -- per-panel rate lookup
  v_use_pkg   boolean := false;
  v_panel     jsonb;
  v_w numeric; v_h numeric; v_q numeric; v_wft numeric; v_hft numeric;
  v_unit text; v_pmat text; v_prv numeric; v_sqft numeric; v_amt numeric;
  v_total_sqft numeric := 0;
  v_subtotal   numeric := 0;
  v_panels     jsonb := '[]'::jsonb;
  v_job_rate   numeric := 0;
  v_inst_rate  numeric := 0;
  v_inst_amt   numeric := 0;
  v_expected   numeric := 0;
  v_status     text;
  v_sk_url text; v_sk_path text; v_pf_url text; v_pf_path text;
  v_site   jsonb;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  if v_mall = '' then raise exception 'Mall is required.'; end if;
  if v_lot  = '' then raise exception 'Lot number is required.'; end if;

  v_type := case when payload->>'jobType' in ('print_install','print_only','install_only')
                 then payload->>'jobType' else 'print_install' end;
  v_date := coalesce(nullif(trim(coalesce(payload->>'requestDate','')),'')::date,
                     (now() at time zone 'Asia/Kuala_Lumpur')::date);

  if v_editing then
    v_id := (payload->>'id')::uuid;
    select * into v_old from vis_jobs where id = v_id;
    if not found then raise exception 'Job not found for edit.'; end if;
    v_job_no := v_old.job_no;
  else
    v_id := gen_random_uuid();
    -- atomic sequential job number VIS-YYYY-#### (lock the table like LockService did)
    lock table vis_jobs in share row exclusive mode;
    select coalesce(max((regexp_match(job_no, '^VIS-'||v_year||'-(\d+)$'))[1]::int), 0) + 1
      into v_next from vis_jobs where job_no like 'VIS-'||v_year||'-%';
    v_job_no := 'VIS-'||v_year||'-'||lpad(v_next::text, 4, '0');
  end if;

  -- job-level rate snapshot; package (all-in) rate only applies to print+install
  v_rate := vis_pick_rate(v_mall, v_material, v_type, v_date);
  v_use_pkg := (v_type = 'print_install' and v_rate.id is not null and coalesce(v_rate.package_rate,0) > 0);

  -- recompute panels server-side (identical maths to the GAS panelSqft_/saveJob)
  for v_panel in select * from jsonb_array_elements(coalesce(payload->'panels','[]'::jsonb)) loop
    v_w := coalesce(nullif(trim(coalesce(v_panel->>'widthVal','')),'')::numeric, 0);
    v_h := coalesce(nullif(trim(coalesce(v_panel->>'heightVal','')),'')::numeric, 0);
    if v_w = 0 and v_h = 0 then continue; end if;
    v_q    := coalesce(nullif(trim(coalesce(v_panel->>'qty','')),'')::numeric, 1);
    if v_q = 0 then v_q := 1; end if;
    v_unit := case when v_panel->>'unit' in ('mm','cm','m','in','ft') then v_panel->>'unit' else 'mm' end;
    v_wft  := case v_unit when 'mm' then v_w/304.8 when 'cm' then v_w/30.48
                          when 'm' then v_w*3.280839895 when 'in' then v_w/12 else v_w end;
    v_hft  := case v_unit when 'mm' then v_h/304.8 when 'cm' then v_h/30.48
                          when 'm' then v_h*3.280839895 when 'in' then v_h/12 else v_h end;
    v_sqft := round(v_wft * v_hft * v_q, 2);
    v_pmat := coalesce(nullif(trim(coalesce(v_panel->>'material','')),''), v_material);
    -- per-panel rate: explicit > install-only (install rate) > package > print rate
    v_prv := coalesce(nullif(trim(coalesce(v_panel->>'ratePerSqft','')),'')::numeric, 0);
    if v_prv = 0 then
      if v_type = 'install_only' then
        v_prate := vis_pick_rate(v_mall, v_pmat, v_type, v_date);
        v_prv := coalesce(v_prate.install_rate, 0);
      elsif v_use_pkg then
        v_prv := v_rate.package_rate;
      else
        v_prate := vis_pick_rate(v_mall, v_pmat, v_type, v_date);
        v_prv := coalesce(v_prate.rate_per_sqft, 0);
      end if;
    end if;
    v_amt := round(v_sqft * v_prv, 2);
    v_total_sqft := round(v_total_sqft + v_sqft, 2);
    v_subtotal   := round(v_subtotal + v_amt, 2);
    v_panels := v_panels || jsonb_build_object(
      'label', coalesce(v_panel->>'label',''), 'width_val', v_w, 'height_val', v_h,
      'unit', v_unit, 'qty', v_q, 'sqft', v_sqft, 'material', v_pmat,
      'rate_per_sqft', v_prv, 'amount', v_amt);
  end loop;

  v_job_rate  := case when v_type = 'install_only' then coalesce(v_rate.install_rate,0)
                      when v_use_pkg then v_rate.package_rate
                      else coalesce(v_rate.rate_per_sqft,0) end;
  v_inst_rate := coalesce(v_rate.install_rate,0);
  -- separate install line only for print+install on the split (non-package) rate
  v_inst_amt  := case when v_type = 'print_install' and not v_use_pkg
                      then round(v_total_sqft * v_inst_rate, 2) else 0 end;
  v_expected  := round(v_subtotal + v_inst_amt, 2);
  if v_rate.id is not null and coalesce(v_rate.min_charge,0) > 0 and v_expected < v_rate.min_charge then
    v_expected := round(v_rate.min_charge, 2);
  end if;

  -- sketch & proof: new upload > pasted link > existing value
  v_sk_url  := case when v_editing then v_old.sketch_url  else '' end;
  v_sk_path := case when v_editing then v_old.sketch_path else '' end;
  if coalesce(payload->>'sketchPath','') <> '' then
    v_sk_path := payload->>'sketchPath'; v_sk_url := '';
  elsif trim(coalesce(payload->>'sketchLink','')) <> '' then
    v_sk_url := trim(payload->>'sketchLink'); v_sk_path := '';
  end if;
  v_pf_url  := case when v_editing then v_old.artwork_proof_url  else '' end;
  v_pf_path := case when v_editing then v_old.artwork_proof_path else '' end;
  if coalesce(payload->>'proofPath','') <> '' then
    v_pf_path := payload->>'proofPath'; v_pf_url := '';
  elsif trim(coalesce(payload->>'proofLink','')) <> '' then
    v_pf_url := trim(payload->>'proofLink'); v_pf_path := '';
  end if;
  -- site photos: append new uploads to the existing set
  v_site := coalesce(case when v_editing then v_old.site_photo_paths end, '[]'::jsonb)
            || coalesce(payload->'sitePhotoPaths','[]'::jsonb);

  v_status := case when payload->>'status' in ('NEW','DRAFT_IN','SENT_CLIENT','ARTWORK_REJECTED',
                        'APPROVED','PRINTING','INSTALLED','COMPLETED','CANCELLED')
                   then payload->>'status'
                   when v_editing then v_old.status else 'NEW' end;

  if v_editing then
    update vis_jobs set
      status = v_status, mall = v_mall, lot_no = v_lot, job_type = v_type,
      client = trim(coalesce(payload->>'client','')),
      requested_by = coalesce(nullif(trim(coalesce(payload->>'requestedBy','')),''), current_email()),
      request_date = v_date,
      install_date = nullif(trim(coalesce(payload->>'installDate','')),'')::date,
      artwork_link = trim(coalesce(payload->>'artworkLink','')),
      artwork_proof_url = v_pf_url, artwork_proof_path = v_pf_path,
      sketch_url = v_sk_url, sketch_path = v_sk_path,
      site_photo_paths = v_site,
      material = v_material, total_sqft = v_total_sqft,
      rate_id = v_rate.id, rate_per_sqft = v_job_rate, install_rate = v_inst_rate,
      subtotal = v_subtotal, expected_amount = v_expected,
      permit_id = nullif(trim(coalesce(payload->>'permitId','')),'')::uuid,
      notes = trim(coalesce(payload->>'notes','')),
      updated_at = now()
    where id = v_id;
    delete from vis_job_panels where job_id = v_id;   -- replace panels
  else
    insert into vis_jobs (id, job_no, status, mall, lot_no, job_type, client, requested_by,
      request_date, install_date, artwork_link, artwork_proof_url, artwork_proof_path,
      sketch_url, sketch_path, site_photo_paths, material, total_sqft, rate_id,
      rate_per_sqft, install_rate, subtotal, expected_amount, permit_id, notes, created_by)
    values (v_id, v_job_no, v_status, v_mall, v_lot, v_type,
      trim(coalesce(payload->>'client','')),
      coalesce(nullif(trim(coalesce(payload->>'requestedBy','')),''), current_email()),
      v_date, nullif(trim(coalesce(payload->>'installDate','')),'')::date,
      trim(coalesce(payload->>'artworkLink','')), v_pf_url, v_pf_path,
      v_sk_url, v_sk_path, v_site, v_material, v_total_sqft, v_rate.id,
      v_job_rate, v_inst_rate, v_subtotal, v_expected,
      nullif(trim(coalesce(payload->>'permitId','')),'')::uuid,
      trim(coalesce(payload->>'notes','')), current_email());
  end if;

  insert into vis_job_panels (job_id, label, width_val, height_val, unit, qty, sqft, material, rate_per_sqft, amount)
  select v_id, p->>'label', (p->>'width_val')::numeric, (p->>'height_val')::numeric,
         p->>'unit', (p->>'qty')::numeric, (p->>'sqft')::numeric, p->>'material',
         (p->>'rate_per_sqft')::numeric, (p->>'amount')::numeric
  from jsonb_array_elements(v_panels) as p;

  -- rememberMall_
  if lower(v_mall) <> 'all' then
    insert into vis_malls (name) values (v_mall) on conflict (name) do nothing;
  end if;

  perform log_audit(case when v_editing then 'vis.job.update' else 'vis.job.create' end,
    v_job_no||' · '||v_mall||' · Lot '||v_lot||' · '||v_total_sqft||' sqft · RM '||v_expected);

  return jsonb_build_object('ok', true, 'id', v_id, 'jobNo', v_job_no,
                            'totalSqft', v_total_sqft, 'expectedAmount', v_expected);
end;
$$;

-- ─── SAVE INVOICE RPC — logs B's invoice + lines, runs the reconciliation ────
-- Tolerance: OK when |claimed − recorded| ≤ RM 5 OR ≤ 1% (same as RECON_TOL_*).
-- payload: { id?, invNo, invDate, period, status?, notes, claimedAmount, sstEnabled,
--            filePath?, fileUrl?, lines:[{jobId, claimedSqft, claimedAmount}] }
create or replace function vis_save_invoice(payload jsonb) returns jsonb
language plpgsql security definer set search_path = public as $$
declare
  v_editing boolean := coalesce(payload->>'id','') <> '';
  v_id      uuid;
  v_old     vis_invoices;
  v_line    jsonb;
  v_job     vis_jobs;
  v_malls   text[] := '{}';
  v_csqft numeric; v_camt numeric; v_ramt numeric; v_rsqft numeric;
  v_diff numeric; v_pct numeric; v_flag text;
  v_line_claim numeric := 0; v_line_rec numeric := 0; v_flagged int := 0; v_count int := 0;
  v_links jsonb := '[]'::jsonb;
  v_claimed numeric; v_sst_on boolean; v_sst numeric; v_ctotal numeric;
  v_verdict text; v_note text;
  v_furl text; v_fpath text; v_status text;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  if trim(coalesce(payload->>'invNo','')) = '' then raise exception 'B''s invoice number is required.'; end if;

  if v_editing then
    v_id := (payload->>'id')::uuid;
    select * into v_old from vis_invoices where id = v_id;
    if not found then raise exception 'Invoice not found.'; end if;
  else
    v_id := gen_random_uuid();
  end if;

  for v_line in select * from jsonb_array_elements(coalesce(payload->'lines','[]'::jsonb)) loop
    if coalesce(v_line->>'jobId','') = '' then continue; end if;
    select * into v_job from vis_jobs where id = (v_line->>'jobId')::uuid;
    v_rsqft := coalesce(v_job.total_sqft, 0);
    v_ramt  := coalesce(v_job.expected_amount, 0);
    if v_job.mall is not null and not (v_job.mall = any(v_malls)) then
      v_malls := v_malls || v_job.mall;
    end if;
    v_csqft := round(coalesce(nullif(trim(coalesce(v_line->>'claimedSqft','')),'')::numeric, 0), 2);
    v_camt  := round(coalesce(nullif(trim(coalesce(v_line->>'claimedAmount','')),'')::numeric, 0), 2);
    v_line_claim := round(v_line_claim + v_camt, 2);
    v_line_rec   := round(v_line_rec + v_ramt, 2);
    v_diff := abs(v_camt - v_ramt);
    v_pct  := case when v_ramt <> 0 then v_diff / abs(v_ramt) when v_diff <> 0 then 1 else 0 end;
    v_flag := case when v_diff <= 5.00 or v_pct <= 0.01 then 'OK'
                   when v_camt > v_ramt then 'OVER' else 'UNDER' end;
    if v_flag <> 'OK' then v_flagged := v_flagged + 1; end if;
    v_count := v_count + 1;
    v_links := v_links || jsonb_build_object(
      'job_id', v_line->>'jobId', 'claimed_sqft', v_csqft, 'claimed_amount', v_camt,
      'recorded_sqft', v_rsqft, 'recorded_amount', v_ramt,
      'variance_rm', round(v_camt - v_ramt, 2), 'flag', v_flag);
  end loop;

  v_claimed := coalesce(nullif(trim(coalesce(payload->>'claimedAmount','')),'')::numeric, 0);
  if v_claimed = 0 then v_claimed := v_line_claim; end if;
  v_claimed := round(v_claimed, 2);
  v_sst_on  := coalesce((payload->>'sstEnabled')::boolean, false);
  v_sst     := case when v_sst_on then round(v_claimed * 0.06, 2) else 0 end;
  v_ctotal  := round(v_claimed + v_sst, 2);
  v_verdict := case when v_flagged > 0 then 'CHECK' else 'MATCH' end;
  v_note    := case when v_flagged > 0
    then v_flagged||' of '||v_count||' job(s) differ from HG record · claimed RM '||v_line_claim||' vs recorded RM '||v_line_rec
    else v_count||' job(s) tally with HG record' end;

  -- invoice file: new upload/link replaces; else keep existing
  v_furl  := case when v_editing then v_old.file_url  else '' end;
  v_fpath := case when v_editing then v_old.file_path else '' end;
  if coalesce(payload->>'filePath','') <> '' then
    v_fpath := payload->>'filePath'; v_furl := '';
  elsif coalesce(payload->>'fileUrl','') <> '' then
    v_furl := payload->>'fileUrl';
  end if;

  v_status := coalesce(nullif(trim(coalesce(payload->>'status','')),''),
                       case when v_verdict = 'MATCH' then 'verified' else 'checking' end);

  if v_editing then
    update vis_invoices set
      inv_no = trim(payload->>'invNo'),
      inv_date = coalesce(nullif(trim(coalesce(payload->>'invDate','')),'')::date,
                          (now() at time zone 'Asia/Kuala_Lumpur')::date),
      period = trim(coalesce(payload->>'period','')),
      malls = array_to_string(v_malls, ', '),
      claimed_amount = v_claimed, sst_enabled = v_sst_on, sst_amount = v_sst, claimed_total = v_ctotal,
      file_url = v_furl, file_path = v_fpath, status = v_status,
      recon_verdict = v_verdict, recon_note = v_note,
      notes = trim(coalesce(payload->>'notes','')), updated_at = now()
    where id = v_id;
    delete from vis_invoice_jobs where invoice_id = v_id;
  else
    insert into vis_invoices (id, inv_no, inv_date, period, malls, claimed_amount, sst_enabled,
      sst_amount, claimed_total, file_url, file_path, status, recon_verdict, recon_note, notes, created_by)
    values (v_id, trim(payload->>'invNo'),
      coalesce(nullif(trim(coalesce(payload->>'invDate','')),'')::date,
               (now() at time zone 'Asia/Kuala_Lumpur')::date),
      trim(coalesce(payload->>'period','')), array_to_string(v_malls, ', '),
      v_claimed, v_sst_on, v_sst, v_ctotal, v_furl, v_fpath, v_status,
      v_verdict, v_note, trim(coalesce(payload->>'notes','')), current_email());
  end if;

  insert into vis_invoice_jobs (invoice_id, job_id, claimed_sqft, claimed_amount,
                                recorded_sqft, recorded_amount, variance_rm, flag)
  select v_id, (l->>'job_id')::uuid, (l->>'claimed_sqft')::numeric, (l->>'claimed_amount')::numeric,
         (l->>'recorded_sqft')::numeric, (l->>'recorded_amount')::numeric,
         (l->>'variance_rm')::numeric, l->>'flag'
  from jsonb_array_elements(v_links) as l;

  perform log_audit(case when v_editing then 'vis.invoice.update' else 'vis.invoice.create' end,
    trim(payload->>'invNo')||' · '||v_verdict||' · '||v_count||' job(s) · claimed RM '||v_claimed||' · '||v_note);

  return jsonb_build_object('ok', true, 'id', v_id, 'verdict', v_verdict,
    'flagged', v_flagged, 'claimedTotal', v_ctotal, 'reconNote', v_note);
end;
$$;

-- ─── ALARMS VIEW — for the daily-alarms edge function + the dashboard ────────
-- Permits expiring within 14 days (or expired); worker docs within 30 days.
create or replace view vis_alarms
with (security_invoker = true) as
select 'permit_expiry'::text as alarm_type,
       coalesce(nullif(p.permit_no,''), nullif(p.permit_type,''), 'permit') as ref,
       'Permit · '||p.mall
         || case when coalesce(p.lot_no,'') <> '' then ' · Lot '||p.lot_no else '' end
         || case when coalesce(p.permit_type,'') <> '' then ' · '||p.permit_type else '' end as detail,
       p.valid_to as due_date,
       coalesce((select value from app_settings where key = 'COMPANY_EMAIL'), '') as recipient
from vis_permits p
where p.valid_to is not null
  and p.valid_to <= (now() at time zone 'Asia/Kuala_Lumpur')::date + 14
union all
select 'worker_doc_expiry', w.name, 'Worker doc · '||w.name||' · CIDB Green Card', w.cidb_expiry,
       coalesce((select value from app_settings where key = 'COMPANY_EMAIL'), '')
from vis_workers w
where lower(coalesce(w.status,'')) <> 'inactive' and w.cidb_expiry is not null
  and w.cidb_expiry <= (now() at time zone 'Asia/Kuala_Lumpur')::date + 30
union all
select 'worker_doc_expiry', w.name, 'Worker doc · '||w.name||' · Work at Height (WAH)', w.wah_expiry,
       coalesce((select value from app_settings where key = 'COMPANY_EMAIL'), '')
from vis_workers w
where lower(coalesce(w.status,'')) <> 'inactive' and w.wah_expiry is not null
  and w.wah_expiry <= (now() at time zone 'Asia/Kuala_Lumpur')::date + 30
union all
select 'worker_doc_expiry', w.name,
       'Worker doc · '||w.name||' · '||coalesce(nullif(w.doc_type,''),'Document'), w.doc_expiry,
       coalesce((select value from app_settings where key = 'COMPANY_EMAIL'), '')
from vis_workers w
where lower(coalesce(w.status,'')) <> 'inactive' and w.doc_expiry is not null
  and w.doc_expiry <= (now() at time zone 'Asia/Kuala_Lumpur')::date + 30;

-- Done. Open visual-supabase.html, connect once, sign in with an allowlisted account.

-- ========== MODULE: schema-dispatch ==========
-- ============================================================================
-- HG GROUP — DAILY JOB READINESS & DISPATCH · Supabase schema (slug: dispatch)
-- Prefix: dsp_ · Run AFTER supabase/schema.sql (the foundation).
-- Additive & idempotent — safe to re-run.
--
-- What it creates:
--   1. dsp_jobs      — every confirmed hoarding job + its readiness gates
--   2. dsp_teams     — night-install crews (one row per dispatch night per team no)
--   3. dsp_staff     — drivers cum supervisors + workers
--   4. dsp_lorries   — lorry master list
--   5. dsp_config    — readiness rules (permit lead days, at-risk window, team caps)
--   6. dsp_save_job()— security-definer RPC: atomic J-#### job code + audit
--   7. dsp_alarms    — view read by the shared `daily-alarms` Edge Function
--                      (permit alarms / at-risk / blocked — same list shown in UI)
--   8. RLS on every table (allowlist-gated via is_allowed())
-- ============================================================================

-- ─── 1 · JOBS ────────────────────────────────────────────────────────────────
create table if not exists dsp_jobs (
  id                 uuid primary key default gen_random_uuid(),
  job_code           text not null default '',        -- J-0001 style, assigned by dsp_save_job()
  client             text not null default '',
  client_group       text not null default '',        -- client WhatsApp group chat name
  mall               text not null default '',
  lot_no             text not null default '',
  job_type           text not null default 'install', -- install|dismantle|rectify|modify|other
  scope              text not null default '',        -- e.g. "12m hoarding"
  door_type          text not null default 'None',
  install_date       date,
  measure_status     text not null default 'pending', -- pending|sketch_done|not_required
  sketch_url         text not null default '',
  quote_status       text not null default 'pending', -- pending|sent|confirmed|not_required
  quote_ref          text not null default '',
  needs_visual       text not null default 'no',      -- yes|no
  visual_status      text not null default 'na',      -- na|pending|approved
  visual_url         text not null default '',
  permit_by          text not null default 'us',      -- us|client|already_have|not_required
  permit_status      text not null default 'pending', -- not_required|pending|submitted|approved
  permit_url         text not null default '',
  permit_approved_at date,
  material_ready     text not null default 'no',      -- yes|no
  material_notes     text not null default '',
  job_status         text not null default 'open',    -- open|assigned|done|cancelled
  dispatch_date      date,                            -- the night it is loaded into a team
  team_no            text not null default '',
  seq                text not null default '',
  notes              text not null default '',
  created_at         timestamptz default now(),
  created_by         text default '',
  updated_at         timestamptz default now(),
  updated_by         text default ''
);
create index if not exists idx_dsp_jobs_install  on dsp_jobs (install_date);
create index if not exists idx_dsp_jobs_dispatch on dsp_jobs (dispatch_date, team_no);

-- ─── 2 · TEAMS (crew per night per team number) ─────────────────────────────
create table if not exists dsp_teams (
  id            uuid primary key default gen_random_uuid(),
  dispatch_date date not null,
  team_no       text not null,
  driver        text not null default '',   -- driver cum supervisor
  workers       text not null default '',   -- comma-separated names
  lorry         text not null default '',   -- plate
  notes         text not null default '',
  created_at    timestamptz default now(),
  created_by    text default '',
  updated_at    timestamptz default now(),
  updated_by    text default '',
  unique (dispatch_date, team_no)
);

-- ─── 3 · STAFF ───────────────────────────────────────────────────────────────
create table if not exists dsp_staff (
  id         uuid primary key default gen_random_uuid(),
  name       text not null,
  role       text not null default 'worker',  -- driver | worker
  phone      text not null default '',
  active     boolean not null default true,
  created_at timestamptz default now(),
  created_by text default '',
  updated_at timestamptz default now(),
  updated_by text default ''
);

-- ─── 4 · LORRIES ─────────────────────────────────────────────────────────────
create table if not exists dsp_lorries (
  id         uuid primary key default gen_random_uuid(),
  plate      text not null,
  label      text not null default '',        -- 3-tonne / 1-tonne
  active     boolean not null default true,
  created_at timestamptz default now(),
  created_by text default '',
  updated_at timestamptz default now(),
  updated_by text default ''
);

-- ─── 5 · CONFIG (same keys + defaults as the GAS Config sheet seed) ─────────
create table if not exists dsp_config (
  key   text primary key,
  value text default '',
  notes text default ''
);
insert into dsp_config (key, value, notes) values
  ('permitLeadDays',    '3',  'Working days a permit needs before install — drives the permit early-warning'),
  ('atRiskDays',        '3',  'If install date is within N days and the job is not ready → AMBER "at risk"'),
  ('maxTeams',          '12', 'Max night-install teams'),
  ('maxJobsPerTeam',    '5',  'Max jobs per team per night'),
  ('maxWorkersPerTeam', '5',  'Max workers per team (excludes the driver cum supervisor)'),
  ('emailRecipients',   'blacklee@hggroup.com.my', 'Comma-separated — who gets the daily readiness email (sent by the daily-alarms Edge Function)')
on conflict (key) do nothing;

-- ─── 6 · SAVE JOB RPC — atomic sequential J-#### code + stamped audit ────────
-- payload keys are the same camelCase names the GAS saveJob() accepted.
create or replace function dsp_save_job(payload jsonb) returns uuid
language plpgsql security definer set search_path = public as $$
declare
  v_id     uuid;
  v_cur    dsp_jobs%rowtype;
  v_code   text;
  v_next   int;
  v_label  text;
  v_exists boolean := false;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  if coalesce(payload->>'mall','') = '' and coalesce(payload->>'lotNo','') = ''
     and coalesce(payload->>'client','') = '' then
    raise exception 'At minimum a job needs a client, mall, or lot number.';
  end if;

  v_id := coalesce(nullif(payload->>'id','')::uuid, gen_random_uuid());
  select * into v_cur from dsp_jobs where id = v_id;
  v_exists := found;

  -- keep the existing code on update; otherwise mint the next J-#### (max of any digits, like GAS)
  v_code := coalesce(nullif(v_cur.job_code,''), nullif(payload->>'jobCode',''));
  if v_code is null then
    select coalesce(max(nullif(substring(job_code from '(\d+)'),'')::int), 0) + 1
      into v_next from dsp_jobs;
    v_code := 'J-' || lpad(v_next::text, 4, '0');
  end if;

  v_label := concat_ws(' · ', nullif(payload->>'mall',''), nullif(payload->>'lotNo',''),
                              nullif(payload->>'jobType',''));

  if v_exists then
    update dsp_jobs set
      job_code           = v_code,
      client             = coalesce(payload->>'client',''),
      client_group       = coalesce(payload->>'clientGroup',''),
      mall               = coalesce(payload->>'mall',''),
      lot_no             = coalesce(payload->>'lotNo',''),
      job_type           = coalesce(nullif(payload->>'jobType',''), 'install'),
      scope              = coalesce(payload->>'scope',''),
      door_type          = coalesce(payload->>'doorType',''),
      install_date       = nullif(payload->>'installDate','')::date,
      measure_status     = coalesce(nullif(payload->>'measureStatus',''), 'pending'),
      sketch_url         = coalesce(payload->>'sketchUrl',''),
      quote_status       = coalesce(nullif(payload->>'quoteStatus',''), 'pending'),
      quote_ref          = coalesce(payload->>'quoteRef',''),
      needs_visual       = case when payload->>'needsVisual' = 'yes' then 'yes' else 'no' end,
      visual_status      = coalesce(nullif(payload->>'visualStatus',''),
                                    case when payload->>'needsVisual' = 'yes' then 'pending' else 'na' end),
      visual_url         = coalesce(payload->>'visualUrl',''),
      permit_by          = coalesce(nullif(payload->>'permitBy',''), 'us'),
      permit_status      = coalesce(nullif(payload->>'permitStatus',''), 'pending'),
      permit_url         = coalesce(payload->>'permitUrl',''),
      permit_approved_at = nullif(payload->>'permitApprovedAt','')::date,
      material_ready     = case when payload->>'materialReady' = 'yes' then 'yes' else 'no' end,
      material_notes     = coalesce(payload->>'materialNotes',''),
      job_status         = coalesce(nullif(payload->>'jobStatus',''), 'open'),
      dispatch_date      = coalesce(nullif(payload->>'dispatchDate','')::date, v_cur.dispatch_date),
      team_no            = coalesce(nullif(payload->>'teamNo',''), v_cur.team_no, ''),
      seq                = coalesce(payload->>'seq', v_cur.seq, ''),
      notes              = coalesce(payload->>'notes',''),
      updated_at         = now(),
      updated_by         = current_email()
    where id = v_id;
    perform log_audit('UPDATE Job', v_code || ' · ' || v_label);
  else
    insert into dsp_jobs (
      id, job_code, client, client_group, mall, lot_no, job_type, scope, door_type,
      install_date, measure_status, sketch_url, quote_status, quote_ref,
      needs_visual, visual_status, visual_url, permit_by, permit_status, permit_url,
      permit_approved_at, material_ready, material_notes, job_status,
      dispatch_date, team_no, seq, notes, created_by, updated_by)
    values (
      v_id, v_code,
      coalesce(payload->>'client',''), coalesce(payload->>'clientGroup',''),
      coalesce(payload->>'mall',''), coalesce(payload->>'lotNo',''),
      coalesce(nullif(payload->>'jobType',''), 'install'),
      coalesce(payload->>'scope',''), coalesce(payload->>'doorType',''),
      nullif(payload->>'installDate','')::date,
      coalesce(nullif(payload->>'measureStatus',''), 'pending'),
      coalesce(payload->>'sketchUrl',''),
      coalesce(nullif(payload->>'quoteStatus',''), 'pending'),
      coalesce(payload->>'quoteRef',''),
      case when payload->>'needsVisual' = 'yes' then 'yes' else 'no' end,
      coalesce(nullif(payload->>'visualStatus',''),
               case when payload->>'needsVisual' = 'yes' then 'pending' else 'na' end),
      coalesce(payload->>'visualUrl',''),
      coalesce(nullif(payload->>'permitBy',''), 'us'),
      coalesce(nullif(payload->>'permitStatus',''), 'pending'),
      coalesce(payload->>'permitUrl',''),
      nullif(payload->>'permitApprovedAt','')::date,
      case when payload->>'materialReady' = 'yes' then 'yes' else 'no' end,
      coalesce(payload->>'materialNotes',''),
      coalesce(nullif(payload->>'jobStatus',''), 'open'),
      nullif(payload->>'dispatchDate','')::date,
      coalesce(payload->>'teamNo',''), coalesce(payload->>'seq',''),
      coalesce(payload->>'notes',''),
      current_email(), current_email());
    perform log_audit('CREATE Job', v_code || ' · ' || v_label);
  end if;

  return v_id;
end;
$$;

-- ─── 7 · ALARMS VIEW — read by the shared `daily-alarms` Edge Function ──────
-- Mirrors sendDailyDispatchDigest() in the GAS backend:
--   permit_alarm : permit not OK and install within permitLeadDays (incl. overdue)
--   at_risk      : not ready, install in 0–7 days, within atRiskDays, no permit alarm
--   blocked      : not ready and install far out (or no date)
create or replace view dsp_alarms with (security_invoker = on) as
with cfg as (
  select
    coalesce((select nullif(value,'')::int from dsp_config where key = 'permitLeadDays'), 3) as lead_days,
    coalesce((select nullif(value,'')::int from dsp_config where key = 'atRiskDays'),     3) as risk_days,
    coalesce((select nullif(value,'')      from dsp_config where key = 'emailRecipients'),
             'blacklee@hggroup.com.my') as recipients
),
base as (
  select j.*,
         (j.install_date - (now() at time zone 'Asia/Kuala_Lumpur')::date) as days_left,
         (j.permit_status = 'approved' or j.permit_by in ('already_have','not_required')
          or j.permit_status = 'not_required') as permit_ok
  from dsp_jobs j
  where j.job_status not in ('done','cancelled')
),
gated as (
  select b.*,
         array_remove(array[
           case when b.mall = '' or b.lot_no = ''                            then 'Lot / Mall' end,
           case when b.measure_status not in ('sketch_done','not_required')  then 'Measurement sketch' end,
           case when b.quote_status   not in ('confirmed','not_required')    then 'Quotation' end,
           case when not b.permit_ok                                         then 'Permit' end,
           case when b.needs_visual = 'yes' and b.visual_status <> 'approved' then 'Visual artwork' end,
           case when b.material_ready <> 'yes'                               then 'Material / fab' end
         ], null) as missing
  from base b
)
select 'permit_alarm'::text as alarm_type,
       g.job_code           as ref,
       g.mall || ' · ' || g.lot_no || ' · ' || g.client ||
         ' — permit: ' || g.permit_by || ' / ' || g.permit_status as detail,
       g.install_date       as due_date,
       cfg.recipients       as recipient
from gated g, cfg
where not g.permit_ok and g.days_left is not null and g.days_left <= cfg.lead_days
union all
select 'at_risk', g.job_code,
       g.mall || ' · ' || g.lot_no || ' · ' || g.client ||
         ' — missing: ' || array_to_string(g.missing, ', '),
       g.install_date, cfg.recipients
from gated g, cfg
where cardinality(g.missing) > 0
  and not (not g.permit_ok and g.days_left is not null and g.days_left <= cfg.lead_days)
  and g.days_left is not null and g.days_left between 0 and 7
  and g.days_left <= cfg.risk_days
union all
select 'blocked', g.job_code,
       g.mall || ' · ' || g.lot_no || ' · ' || g.client ||
         ' — missing: ' || array_to_string(g.missing, ', '),
       g.install_date, cfg.recipients
from gated g, cfg
where cardinality(g.missing) > 0
  and (g.days_left is null or g.days_left > cfg.risk_days);

grant select on dsp_alarms to authenticated;

-- ─── 8 · ROW-LEVEL SECURITY — allowlist-gated everything ────────────────────
alter table dsp_jobs    enable row level security;
alter table dsp_teams   enable row level security;
alter table dsp_staff   enable row level security;
alter table dsp_lorries enable row level security;
alter table dsp_config  enable row level security;

do $$
declare t text;
begin
  foreach t in array array['dsp_jobs','dsp_teams','dsp_staff','dsp_lorries','dsp_config'] loop
    execute format('drop policy if exists %I_rw on %I', t, t);
    execute format('create policy %I_rw on %I for all to authenticated using (is_allowed()) with check (is_allowed())', t, t);
  end loop;
end $$;

-- Done. The daily permit-alarm email is handled by the shared `daily-alarms`
-- Edge Function reading dsp_alarms — no trigger install needed in this tool.

-- ========== MODULE: schema-workers ==========
-- ============================================================================
-- HG GROUP — WORKERS DOCUMENTATION & WORK PERMITS · Supabase schema (wkr_)
-- Converted from apps-script-workers (Google Apps Script + Sheets).
-- Run AFTER the foundation schema.sql (needs allowed_users, is_allowed(),
-- current_email(), log_audit(), app_settings).
-- Additive + idempotent — safe to re-run.
--
-- Creates:
--   wkr_divisions, wkr_workers, wkr_documents,
--   wkr_work_permits, wkr_permit_workers, wkr_permit_attachments,
--   wkr_permit_forms,
--   wkr_insurance_policies, wkr_insurance_attachments,
--   wkr_insurance_quotes, wkr_insurance_payments,
--   wkr_report_history
--   RPCs: wkr_save_permit(jsonb), wkr_save_insurance(jsonb),
--         wkr_delete_division(uuid)
--   View: wkr_alarms  (read by the shared `daily-alarms` Edge Function + UI)
--   Storage bucket: worker-docs (private)
-- ============================================================================

-- ─── 1 · DIVISIONS ───────────────────────────────────────────────────────────
create table if not exists wkr_divisions (
  id          uuid primary key default gen_random_uuid(),
  name        text not null,
  description text default '',
  active      boolean default true,
  created_by  text default '',
  created_at  timestamptz default now()
);

-- ─── 2 · WORKERS ─────────────────────────────────────────────────────────────
create table if not exists wkr_workers (
  id              uuid primary key default gen_random_uuid(),
  full_name       text not null,
  ic_number       text default '',
  passport_number text default '',
  nationality     text default '',
  division_id     uuid references wkr_divisions(id),
  position        text default '',
  phone           text default '',
  photo_url       text default '',      -- sb://worker-docs/<path> or external URL
  status          text default 'active',  -- active / inactive / resigned
  created_by      text default '',
  created_at      timestamptz default now(),
  updated_by      text default '',
  updated_at      timestamptz default now()
);
create index if not exists idx_wkr_workers_division on wkr_workers (division_id);

-- ─── 3 · DOCUMENTS (per worker; doc_type is the locked 12-key enum in the UI) ─
create table if not exists wkr_documents (
  id                uuid primary key default gen_random_uuid(),
  worker_id         uuid not null references wkr_workers(id) on delete cascade,
  doc_type          text not null,       -- PASSPORT / IC / WORKING_VISA / … / DRIVING_HEAVY
  doc_subtype       text default '',     -- e.g. mall name, competency type, vehicle type
  doc_number        text default '',
  issue_date        date,
  expiry_date       date,
  issuing_authority text default '',
  file_url          text default '',
  notes             text default '',
  created_by        text default '',
  created_at        timestamptz default now(),
  updated_by        text default '',
  updated_at        timestamptz default now()
);
create index if not exists idx_wkr_documents_worker on wkr_documents (worker_id);
create index if not exists idx_wkr_documents_expiry on wkr_documents (expiry_date);

-- ─── 4 · INSURANCE POLICIES (HG's own cover-note library) ────────────────────
create table if not exists wkr_insurance_policies (
  id                uuid primary key default gen_random_uuid(),
  policy_number     text not null,
  provider          text not null,
  coverage_type     text default '',
  coverage_amount   text default '',
  valid_from        date,
  valid_until       date,
  file_url          text default '',
  notes             text default '',
  status            text default 'active',   -- active / expired / cancelled
  invoice_number    text default '',          -- invoice we sent to client
  premium_amount    numeric default 0,        -- cost we pay the insurer (RM)
  charged_to_client numeric default 0,        -- what we bill the client (RM)
  created_by        text default '',
  created_at        timestamptz default now(),
  updated_by        text default '',
  updated_at        timestamptz default now()
);

create table if not exists wkr_insurance_attachments (
  id         uuid primary key default gen_random_uuid(),
  policy_id  uuid not null references wkr_insurance_policies(id) on delete cascade,
  label      text default '',
  file_url   text default '',
  sort_order int default 0
);
create index if not exists idx_wkr_ins_att_policy on wkr_insurance_attachments (policy_id);

create table if not exists wkr_insurance_quotes (
  id         uuid primary key default gen_random_uuid(),
  policy_id  uuid not null references wkr_insurance_policies(id) on delete cascade,
  provider   text default '',
  amount     numeric default 0,
  notes      text default '',
  sort_order int default 0
);
create index if not exists idx_wkr_ins_q_policy on wkr_insurance_quotes (policy_id);

create table if not exists wkr_insurance_payments (
  id           uuid primary key default gen_random_uuid(),
  policy_id    uuid not null references wkr_insurance_policies(id) on delete cascade,
  payment_date date,
  amount       numeric default 0,
  reference    text default '',
  notes        text default '',
  sort_order   int default 0
);
create index if not exists idx_wkr_ins_p_policy on wkr_insurance_payments (policy_id);

-- ─── 5 · WORK PERMITS (issued mall / building permits) ───────────────────────
-- insurance_policy_id has NO cascade — deleting a policy that permits still
-- reference is blocked (same guard as the Apps Script version).
create table if not exists wkr_work_permits (
  id                      uuid primary key default gen_random_uuid(),
  permit_number           text default '',
  title                   text default '',
  mall_name               text default '',
  project_reference       text default '',
  contractor_client       text default '',
  work_scope              text default '',
  work_area               text default '',
  working_hours           text default '',
  applied_by              text default 'own_team',  -- own_team / client / mall
  issued_by               text default '',
  issue_date              date,
  valid_from              date,
  valid_until             date,
  file_url                text default '',           -- the approved permit PDF
  status                  text default 'active',     -- active / cancelled / superseded
  notes                   text default '',
  duration                text default 'ad_hoc',     -- yearly / monthly / ad_hoc
  insurance_source        text default 'none',       -- hg_existing / new / client / none
  insurance_policy_id     uuid references wkr_insurance_policies(id),
  insurance_provider      text default '',
  insurance_policy_number text default '',
  insurance_file_url      text default '',
  insurance_notes         text default '',
  client_invoice_number   text default '',
  created_by              text default '',
  created_at              timestamptz default now(),
  updated_by              text default '',
  updated_at              timestamptz default now()
);
create index if not exists idx_wkr_permits_valid_until on wkr_work_permits (valid_until);

create table if not exists wkr_permit_workers (
  id        uuid primary key default gen_random_uuid(),
  permit_id uuid not null references wkr_work_permits(id) on delete cascade,
  worker_id uuid not null references wkr_workers(id) on delete cascade,
  role      text default ''
);
create index if not exists idx_wkr_pw_permit on wkr_permit_workers (permit_id);
create index if not exists idx_wkr_pw_worker on wkr_permit_workers (worker_id);

create table if not exists wkr_permit_attachments (
  id         uuid primary key default gen_random_uuid(),
  permit_id  uuid not null references wkr_work_permits(id) on delete cascade,
  label      text default '',
  file_url   text default '',
  sort_order int default 0
);
create index if not exists idx_wkr_pa_permit on wkr_permit_attachments (permit_id);

-- ─── 6 · FORM LIBRARY (blank permit forms per mall) ──────────────────────────
create table if not exists wkr_permit_forms (
  id                 uuid primary key default gen_random_uuid(),
  mall_name          text not null,
  form_name          text not null,
  form_type          text default '',
  version            text default '',
  file_url           text default '',
  contact_info       text default '',
  lead_time          text default '',
  requirements       text default '',
  notes              text default '',
  last_verified_date date,
  created_by         text default '',
  created_at         timestamptz default now(),
  updated_by         text default '',
