-- ─── 3 · RPC · SAVE ENGAGEMENT (atomic sequential ENG-0001 ref) ─────────────
-- payload: { id?, clientId, reason, siteName, siteAddress, handledBy, remarks, status? }
create or replace function trn_save_engagement(payload jsonb) returns uuid
language plpgsql security definer set search_path = public as $$
declare
  v_client trn_clients%rowtype;
  v_ex     trn_engagements%rowtype;
  v_prefix text; v_next int; v_ref text; v_id uuid;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  if coalesce(payload->>'clientId','') = '' then raise exception 'Client is required.'; end if;
  select * into v_client from trn_clients where id = (payload->>'clientId')::uuid;
  if not found then raise exception 'Client not found.'; end if;

  if coalesce(payload->>'id','') <> '' then
    select * into v_ex from trn_engagements where id = (payload->>'id')::uuid;
    if not found then raise exception 'Engagement not found.'; end if;
    update trn_engagements set
      client_id = v_client.id, client_company = v_client.company,
      reason = coalesce(nullif(payload->>'reason',''), 'Ad-hoc'),
      site_name = coalesce(payload->>'siteName', site_name),
      site_address = coalesce(payload->>'siteAddress', site_address),
      status = coalesce(nullif(payload->>'status',''), status),
      handled_by = coalesce(payload->>'handledBy', handled_by),
      remarks = coalesce(payload->>'remarks', remarks),
      updated_by = current_email(), updated_at = now()
    where id = v_ex.id;
    -- keep job denormalised client fields in sync
    update trn_jobs set client_company = v_client.company, client_id = v_client.id
      where engagement_id = v_ex.id;
    perform log_audit('UPDATE Engagement', v_ex.ref || ' · ' || v_client.company);
    return v_ex.id;
  end if;

  select coalesce((select nullif(value,'') from trn_settings where key = 'ENG_PREFIX'), 'ENG-') into v_prefix;
  select coalesce(max((substring(ref from length(v_prefix)+1))::int), 0) + 1 into v_next
    from trn_engagements
    where ref like v_prefix || '%' and substring(ref from length(v_prefix)+1) ~ '^[0-9]+$';
  v_ref := v_prefix || lpad(v_next::text, 4, '0');

  insert into trn_engagements (ref, client_id, client_company, reason, site_name, site_address,
                               status, handled_by, remarks, created_by, updated_by)
  values (v_ref, v_client.id, v_client.company,
          coalesce(nullif(payload->>'reason',''), 'Ad-hoc'),
          coalesce(payload->>'siteName',''), coalesce(payload->>'siteAddress',''),
          coalesce(nullif(payload->>'status',''), 'Open'),
          coalesce(nullif(payload->>'handledBy',''), current_email()),
          coalesce(payload->>'remarks',''), current_email(), current_email())
  returning id into v_id;
  perform log_audit('CREATE Engagement', v_ref || ' · ' || v_client.company || ' / ' || coalesce(nullif(payload->>'reason',''),'Ad-hoc'));
  return v_id;
end;
$$;

-- ─── 4 · RPC · SAVE JOB (server-side recompute: rate × qty, bin clash) ──────
-- payload mirrors the Apps Script saveJob(p) argument.
create or replace function trn_save_job(payload jsonb) returns uuid
language plpgsql security definer set search_path = public as $$
declare
  v_eng        trn_engagements%rowtype;
  v_rate       trn_rates%rowtype;
  v_bin        trn_bins%rowtype;
  v_ex         trn_jobs%rowtype;
  v_rate_found boolean := false;
  v_service    text; v_internal boolean; v_manual text; v_has_manual boolean;
  v_qty        numeric; v_amount numeric; v_maxdays numeric;
  v_binid      uuid; v_binno text := '';
  v_stops      jsonb; v_first jsonb; v_last jsonb;
  v_start text; v_end text; v_from text; v_to text;
  v_ratelabel  text; v_id uuid;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  if coalesce(payload->>'engagementId','') = '' then raise exception 'Engagement is required.'; end if;
  v_service := payload->>'service';
  if v_service not in ('Lorry','Mover','Rorobin') then raise exception 'Pick a valid service.'; end if;
  select * into v_eng from trn_engagements where id = (payload->>'engagementId')::uuid;
  if not found then raise exception 'Engagement not found.'; end if;

  v_internal := coalesce((payload->>'internalUse')::boolean, false);
  v_manual := payload->>'manualAmount';
  v_has_manual := (not v_internal) and v_manual is not null and v_manual <> '';

  if coalesce(payload->>'rateCode','') <> '' then
    select * into v_rate from trn_rates where lower(code) = lower(payload->>'rateCode') limit 1;
    v_rate_found := found;
  end if;
  if (not v_internal) and (not v_has_manual) then
    if not v_rate_found then raise exception 'Pick a rate or key a charge amount.'; end if;
    if not v_rate.active then raise exception 'Rate % is inactive — pick an active rate.', v_rate.code; end if;
    if v_rate.service <> v_service then raise exception 'Rate % is for %, not %.', v_rate.code, v_rate.service, v_service; end if;
  end if;

  -- quantity per service
  if v_service = 'Lorry' then
    v_qty := greatest(1, coalesce(nullif(payload->>'trips','')::numeric, 1));
  elsif v_service = 'Mover' then
    v_qty := greatest(1, coalesce(nullif(payload->>'movers','')::numeric, 1)
                       * coalesce(nullif(payload->>'shifts','')::numeric, 1));
  else
    v_qty := greatest(1, coalesce(nullif(payload->>'quantity','')::numeric, 1));
  end if;
  v_amount := case when v_internal then 0
                   when v_has_manual then round(v_manual::numeric, 2)
                   else round(coalesce(v_rate.rate, 0) * v_qty, 2) end;

  -- rorobin bin handling + clash check
  if v_service = 'Rorobin' then
    v_binid := nullif(payload->>'binId','')::uuid;
    if v_binid is null then raise exception 'Select a rorobin bin.'; end if;
    select * into v_bin from trn_bins where id = v_binid;
    if not found then raise exception 'Bin not found.'; end if;
    v_binno := v_bin.bin_no;
    if coalesce(payload->>'collectDateTime','') = ''
       and coalesce(nullif(payload->>'status',''),'Scheduled') not in ('Completed','Cancelled') then
      perform 1 from trn_jobs j
        where j.service = 'Rorobin' and j.bin_id = v_binid
          and j.id is distinct from nullif(payload->>'id','')::uuid
          and j.status not in ('Completed','Cancelled')
          and coalesce(j.collect_datetime,'') = '';
      if found then raise exception 'Bin % is already deployed. Collect it first.', v_binno; end if;
    end if;
  end if;

  v_maxdays := coalesce(nullif(payload->>'maxDays','')::numeric,
                        (select nullif(value,'')::numeric from trn_settings where key = 'ROROBIN_MAX_DAYS'), 3);

  -- multi-stop legs (lorry): derive summary from/to/time when blank
  v_stops := coalesce(payload->'stops', '[]'::jsonb);
  v_start := coalesce(payload->>'startDateTime','');
  v_end   := coalesce(payload->>'endDateTime','');
  v_from  := coalesce(payload->>'fromLocation','');
  v_to    := coalesce(payload->>'toLocation','');
  if v_service = 'Lorry' and jsonb_array_length(v_stops) > 0 then
    v_first := v_stops->0;
    v_last  := v_stops->(jsonb_array_length(v_stops)-1);
    if v_start = '' then v_start := coalesce(v_first->>'pickupDateTime',''); end if;
    if v_end   = '' then v_end   := coalesce(v_last->>'deliveryDateTime',''); end if;
    if v_from  = '' then v_from  := coalesce(v_first->>'pickupLocation',''); end if;
    if v_to    = '' then v_to    := coalesce(v_last->>'deliveryLocation',''); end if;
  end if;

  v_ratelabel := case when v_internal then 'Internal use (no charge)'
                      when v_rate_found then v_rate.label
                      when v_has_manual then 'Keyed charge' else '' end;

  if coalesce(payload->>'id','') <> '' then
    select * into v_ex from trn_jobs where id = (payload->>'id')::uuid;
    if not found then raise exception 'Job not found.'; end if;
    if v_ex.invoice_id is not null then
      raise exception 'Job is already on invoice — void/unlink the invoice before editing the charge.';
    end if;
    update trn_jobs set
      engagement_id = v_eng.id, engagement_ref = v_eng.ref,
      client_id = v_eng.client_id, client_company = v_eng.client_company,
      service = v_service, status = coalesce(nullif(payload->>'status',''), 'Scheduled'),
      stops = v_stops, start_datetime = v_start, end_datetime = v_end,
      from_location = v_from, to_location = v_to,
      lorry_type = coalesce(payload->>'lorryType',''), lorry_plate = coalesce(payload->>'lorryPlate',''),
      driver = coalesce(payload->>'driver',''), trips = coalesce(nullif(payload->>'trips','')::numeric, 0),
      collection_mover_by = coalesce(payload->>'collectionMoverBy',''),
      delivery_mover_by = coalesce(payload->>'deliveryMoverBy',''),
      movers = coalesce(nullif(payload->>'movers','')::numeric, 0),
      shifts = coalesce(nullif(payload->>'shifts','')::numeric, 0),
      items_description = coalesce(payload->>'itemsDescription',''),
      bin_id = v_binid, bin_no = v_binno,
      placement_type = coalesce(payload->>'placementType',''),
      place_datetime = coalesce(payload->>'placeDateTime',''),
      collect_datetime = coalesce(payload->>'collectDateTime',''),
      permit_no = coalesce(payload->>'permitNo',''), swcorp_ref = coalesce(payload->>'swcorpRef',''),
      max_days = v_maxdays,
      rate_code = case when v_rate_found then v_rate.code else '' end,
      rate_label = v_ratelabel,
      unit_rate = coalesce(v_rate.rate, 0), quantity = v_qty, amount = v_amount,
      internal_use = v_internal,
      handled_by = coalesce(nullif(payload->>'handledBy',''), v_eng.handled_by, current_email()),
      remarks = coalesce(payload->>'remarks',''),
      updated_by = current_email(), updated_at = now()
    where id = v_ex.id;
    perform log_audit('UPDATE Job', v_eng.ref || '/' || v_service || ' · ' ||
      case when v_internal then 'Internal (no charge)' else 'RM' || v_amount end);
    return v_ex.id;
  end if;

  insert into trn_jobs (engagement_id, engagement_ref, client_id, client_company, service, status,
    stops, start_datetime, end_datetime, from_location, to_location, lorry_type, lorry_plate, driver,
    trips, collection_mover_by, delivery_mover_by, movers, shifts, items_description,
    bin_id, bin_no, placement_type, place_datetime, collect_datetime, permit_no, swcorp_ref, max_days,
    rate_code, rate_label, unit_rate, quantity, amount, internal_use, handled_by, remarks,
    created_by, updated_by)
  values (v_eng.id, v_eng.ref, v_eng.client_id, v_eng.client_company, v_service,
    coalesce(nullif(payload->>'status',''), 'Scheduled'),
    v_stops, v_start, v_end, v_from, v_to,
    coalesce(payload->>'lorryType',''), coalesce(payload->>'lorryPlate',''), coalesce(payload->>'driver',''),
    coalesce(nullif(payload->>'trips','')::numeric, 0),
    coalesce(payload->>'collectionMoverBy',''), coalesce(payload->>'deliveryMoverBy',''),
    coalesce(nullif(payload->>'movers','')::numeric, 0), coalesce(nullif(payload->>'shifts','')::numeric, 0),
    coalesce(payload->>'itemsDescription',''),
    v_binid, v_binno, coalesce(payload->>'placementType',''),
    coalesce(payload->>'placeDateTime',''), coalesce(payload->>'collectDateTime',''),
    coalesce(payload->>'permitNo',''), coalesce(payload->>'swcorpRef',''), v_maxdays,
    case when v_rate_found then v_rate.code else '' end, v_ratelabel,
    coalesce(v_rate.rate, 0), v_qty, v_amount, v_internal,
    coalesce(nullif(payload->>'handledBy',''), v_eng.handled_by, current_email()),
    coalesce(payload->>'remarks',''), current_email(), current_email())
  returning id into v_id;
  perform log_audit('CREATE Job', v_eng.ref || '/' || v_service || ' · ' ||
    case when v_internal then 'Internal (no charge)'
         else 'RM' || v_amount || ' (' || coalesce(v_rate.code,'-') || ' ×' || v_qty || ')' end);
  return v_id;
end;
$$;

-- ─── 5 · RPC · SAVE TRIP / RUN (atomic sequential RUN-0001 ref) ─────────────
-- payload: { id?, tripDate, shift, status, lorryPlate, driver, driverId, driverCost, lorryCost, notes, crew:[] }
create or replace function trn_save_trip(payload jsonb) returns uuid
language plpgsql security definer set search_path = public as $$
declare
  v_ex trn_trips%rowtype;
  v_prefix text; v_next int; v_ref text; v_id uuid;
  v_crew jsonb := coalesce(payload->'crew', '[]'::jsonb);
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;

  if coalesce(payload->>'id','') <> '' then
    select * into v_ex from trn_trips where id = (payload->>'id')::uuid;
    if not found then raise exception 'Trip not found.'; end if;
    update trn_trips set
      trip_date = coalesce(nullif(payload->>'tripDate',''), (now() at time zone 'Asia/Kuala_Lumpur')::date::text),
      shift = case when payload->>'shift' = 'Night' then 'Night' else 'Day' end,
      lorry_plate = coalesce(payload->>'lorryPlate',''), driver = coalesce(payload->>'driver',''),
      driver_id = nullif(payload->>'driverId','')::uuid,
      driver_cost = round(coalesce(nullif(payload->>'driverCost','')::numeric, 0), 2),
      lorry_cost = round(coalesce(nullif(payload->>'lorryCost','')::numeric, 0), 2),
      crew = v_crew, status = coalesce(nullif(payload->>'status',''), 'Planned'),
      notes = coalesce(payload->>'notes',''),
      updated_by = current_email(), updated_at = now()
    where id = v_ex.id;
    perform log_audit('UPDATE Trip', v_ex.ref || ' · ' || coalesce(payload->>'lorryPlate','') ||
      ' · ' || jsonb_array_length(v_crew) || ' crew');
    return v_ex.id;
  end if;

  select coalesce((select nullif(value,'') from trn_settings where key = 'TRIP_PREFIX'), 'RUN-') into v_prefix;
  select coalesce(max((substring(ref from length(v_prefix)+1))::int), 0) + 1 into v_next
    from trn_trips
    where ref like v_prefix || '%' and substring(ref from length(v_prefix)+1) ~ '^[0-9]+$';
  v_ref := v_prefix || lpad(v_next::text, 4, '0');

  insert into trn_trips (ref, trip_date, shift, lorry_plate, driver, driver_id, driver_cost, lorry_cost,
                         crew, status, notes, created_by, updated_by)
  values (v_ref,
    coalesce(nullif(payload->>'tripDate',''), (now() at time zone 'Asia/Kuala_Lumpur')::date::text),
    case when payload->>'shift' = 'Night' then 'Night' else 'Day' end,
    coalesce(payload->>'lorryPlate',''), coalesce(payload->>'driver',''),
    nullif(payload->>'driverId','')::uuid,
    round(coalesce(nullif(payload->>'driverCost','')::numeric, 0), 2),
    round(coalesce(nullif(payload->>'lorryCost','')::numeric, 0), 2),
    v_crew, coalesce(nullif(payload->>'status',''), 'Planned'), coalesce(payload->>'notes',''),
    current_email(), current_email())
  returning id into v_id;
  perform log_audit('CREATE Trip', v_ref || ' · ' || coalesce(payload->>'lorryPlate','') ||
    ' · ' || jsonb_array_length(v_crew) || ' crew');
  return v_id;
end;
$$;

-- ─── 6 · RPC · ASSIGN JOBS TO TRIP (stops appended after max stop seq) ──────
create or replace function trn_assign_jobs_to_trip(p_trip_id uuid, p_job_ids uuid[]) returns void
language plpgsql security definer set search_path = public as $$
declare
  v_trip trn_trips%rowtype;
  v_seq int; v_jid uuid; v_job trn_jobs%rowtype;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  select * into v_trip from trn_trips where id = p_trip_id;
  if not found then raise exception 'Trip not found.'; end if;
  select coalesce(max(stop_seq), 0) into v_seq from trn_jobs where trip_id = p_trip_id;
  foreach v_jid in array coalesce(p_job_ids, '{}') loop
    select * into v_job from trn_jobs where id = v_jid;
    if not found then continue; end if;
    if v_job.trip_id is not null and v_job.trip_id <> p_trip_id then
      raise exception 'A job is already on another run (%). Remove it first.', v_job.engagement_ref;
    end if;
    v_seq := v_seq + 1;
    update trn_jobs set trip_id = p_trip_id, stop_seq = v_seq where id = v_jid;
  end loop;
  perform log_audit('TRIP_ASSIGN', v_trip.ref || ' · ' || coalesce(array_length(p_job_ids,1),0) || ' stop(s)');
end;
$$;

-- ─── 7 · RPC · ADD RUN STOP (run-first billable stop; auto Transport engmnt) ─
-- payload: { tripId, clientId, lorry, lorryCharge, mover, moverCharge, workers:[],
--            pickupLocation, pickupDateTime, deliveryLocation, deliveryDateTime,
--            notes, internalUse, status? }
create or replace function trn_add_run_stop(payload jsonb) returns void
language plpgsql security definer set search_path = public as $$
declare
  v_trip trn_trips%rowtype;
  v_client trn_clients%rowtype;
  v_eng trn_engagements%rowtype;
  v_prefix text; v_next int; v_ref text;
  v_lorry_charge numeric; v_mover_charge numeric;
  v_internal boolean; v_want_lorry boolean; v_want_mover boolean;
  v_seq int; v_workers jsonb; v_nworkers int;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  select * into v_trip from trn_trips where id = nullif(payload->>'tripId','')::uuid;
  if not found then raise exception 'Run not found.'; end if;
  if coalesce(payload->>'clientId','') = '' then raise exception 'Select a client for this stop.'; end if;
  select * into v_client from trn_clients where id = (payload->>'clientId')::uuid;
  if not found then raise exception 'Client not found.'; end if;

  v_lorry_charge := round(coalesce(nullif(payload->>'lorryCharge','')::numeric, 0), 2);
  v_mover_charge := round(coalesce(nullif(payload->>'moverCharge','')::numeric, 0), 2);
  v_internal := coalesce((payload->>'internalUse')::boolean, false);
  v_want_lorry := coalesce((payload->>'lorry')::boolean, false) or v_lorry_charge > 0;
  v_want_mover := coalesce((payload->>'mover')::boolean, false) or v_mover_charge > 0;
  if not v_want_lorry and not v_want_mover then
    raise exception 'Tick Lorry and/or Mover for this stop (with a charge, or mark internal).';
  end if;

  -- find or create the client's auto "Transport" engagement
  select * into v_eng from trn_engagements
    where client_id = v_client.id and reason = 'Transport' and status <> 'Cancelled'
    order by created_at limit 1;
  if not found then
    select coalesce((select nullif(value,'') from trn_settings where key = 'ENG_PREFIX'), 'ENG-') into v_prefix;
    select coalesce(max((substring(ref from length(v_prefix)+1))::int), 0) + 1 into v_next
      from trn_engagements
      where ref like v_prefix || '%' and substring(ref from length(v_prefix)+1) ~ '^[0-9]+$';
    v_ref := v_prefix || lpad(v_next::text, 4, '0');
    insert into trn_engagements (ref, client_id, client_company, reason, status, handled_by, remarks,
                                 created_by, updated_by)
    values (v_ref, v_client.id, v_client.company, 'Transport', 'Open', current_email(),
            'Auto-created for transport runs', current_email(), current_email())
    returning * into v_eng;
    perform log_audit('CREATE Engagement', v_ref || ' · ' || v_client.company || ' / Transport (auto)');
  end if;

  select coalesce(max(stop_seq), 0) into v_seq from trn_jobs where trip_id = v_trip.id;
  v_workers := coalesce(payload->'workers', '[]'::jsonb);
  v_nworkers := jsonb_array_length(v_workers);

  if v_want_lorry then
    v_seq := v_seq + 1;
    insert into trn_jobs (engagement_id, engagement_ref, client_id, client_company, service, status,
      start_datetime, end_datetime, from_location, to_location, items_description,
      lorry_plate, driver, trips, movers, shifts, quantity, unit_rate, amount, rate_label,
      internal_use, handled_by, trip_id, stop_seq, stops, created_by, updated_by)
    values (v_eng.id, v_eng.ref, v_client.id, v_client.company, 'Lorry',
      coalesce(nullif(payload->>'status',''), 'Scheduled'),
      coalesce(payload->>'pickupDateTime',''), coalesce(payload->>'deliveryDateTime',''),
      coalesce(payload->>'pickupLocation',''), coalesce(payload->>'deliveryLocation',''),
      coalesce(payload->>'notes',''),
      v_trip.lorry_plate, v_trip.driver, 1, 0, 0, 1,
      case when v_internal then 0 else v_lorry_charge end,
      case when v_internal then 0 else v_lorry_charge end,
      case when v_internal then 'Internal use (no charge)' else 'Keyed charge' end,
      v_internal, coalesce(nullif(payload->>'handledBy',''), nullif(v_trip.driver,''), current_email()),
      v_trip.id, v_seq, '[]'::jsonb, current_email(), current_email());
  end if;

  if v_want_mover then
    v_seq := v_seq + 1;
    insert into trn_jobs (engagement_id, engagement_ref, client_id, client_company, service, status,
      start_datetime, end_datetime, from_location, to_location, items_description,
      lorry_plate, driver, trips, movers, shifts, quantity, unit_rate, amount, rate_label,
      internal_use, handled_by, trip_id, stop_seq, stops, remarks, created_by, updated_by)
    values (v_eng.id, v_eng.ref, v_client.id, v_client.company, 'Mover',
      coalesce(nullif(payload->>'status',''), 'Scheduled'),
      coalesce(payload->>'pickupDateTime',''), coalesce(payload->>'deliveryDateTime',''),
      coalesce(payload->>'pickupLocation',''), coalesce(payload->>'deliveryLocation',''),
      coalesce(payload->>'notes',''),
      v_trip.lorry_plate, v_trip.driver, 0,
      greatest(1, coalesce(nullif(v_nworkers,0), coalesce(nullif(payload->>'moverCount','')::int, 1))), 1, 1,
      case when v_internal then 0 else v_mover_charge end,
      case when v_internal then 0 else v_mover_charge end,
      case when v_internal then 'Internal use (no charge)' else 'Keyed charge' end,
      v_internal, coalesce(nullif(payload->>'handledBy',''), nullif(v_trip.driver,''), current_email()),
      v_trip.id, v_seq, '[]'::jsonb,
      case when v_nworkers > 0 then 'Crew: ' ||
        (select string_agg(w #>> '{}', ', ') from jsonb_array_elements(v_workers) w) else '' end,
      current_email(), current_email());
  end if;

  perform log_audit('RUN_STOP', v_trip.ref || ' · ' || v_client.company ||
    case when v_want_lorry then ' · Lorry ' || case when v_internal then 'internal' else 'RM' || v_lorry_charge end else '' end ||
    case when v_want_mover then ' · Mover ' || case when v_internal then 'internal' else 'RM' || v_mover_charge end else '' end);
end;
$$;

-- ─── 8 · RPC · SAVE INVOICE (sums selected jobs, SST 6%, stamps jobs) ───────
-- payload: { id?, invNo, engagementId, jobIds:[], invDate, dueDate, sstEnabled,
--            notes, description?, filePath?, status? }
create or replace function trn_save_invoice(payload jsonb) returns uuid
language plpgsql security definer set search_path = public as $$
declare
  v_eng trn_engagements%rowtype;
  v_ex  trn_invoices%rowtype;
  v_job trn_jobs%rowtype;
  v_ids uuid[]; v_jid uuid;
  v_amount numeric := 0; v_sst_on boolean; v_sst numeric; v_total numeric;
  v_desc text; v_services text := ''; v_id uuid; v_count int := 0;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  if coalesce(payload->>'invNo','') = '' then raise exception 'Invoice number is required.'; end if;
  if coalesce(payload->>'engagementId','') = '' then raise exception 'Engagement is required.'; end if;
  if coalesce(payload->>'invDate','') = '' then raise exception 'Invoice date is required.'; end if;
  if jsonb_array_length(coalesce(payload->'jobIds','[]'::jsonb)) = 0 then
    raise exception 'Select at least one job to bill.';
  end if;
  select * into v_eng from trn_engagements where id = (payload->>'engagementId')::uuid;
  if not found then raise exception 'Engagement not found.'; end if;

  -- unique invoice number
  perform 1 from trn_invoices
    where lower(inv_no) = lower(trim(payload->>'invNo'))
      and id is distinct from nullif(payload->>'id','')::uuid;
  if found then raise exception 'Invoice number % already exists.', payload->>'invNo'; end if;

  select array_agg(x::uuid) into v_ids from jsonb_array_elements_text(payload->'jobIds') x;
  foreach v_jid in array v_ids loop
    select * into v_job from trn_jobs where id = v_jid;
    if not found then raise exception 'Some selected jobs were not found.'; end if;
    if v_job.engagement_id <> v_eng.id then
      raise exception 'Job % is not in this engagement.', v_job.service;
    end if;
    if v_job.invoice_id is not null and v_job.invoice_id is distinct from nullif(payload->>'id','')::uuid then
      raise exception 'Job %/% is already on another invoice.', v_job.engagement_ref, v_job.service;
    end if;
    v_amount := v_amount + coalesce(v_job.amount, 0);
    v_count := v_count + 1;
    v_services := v_services || case when v_services = '' then '' else ' + ' end || v_job.service;
  end loop;
  v_amount := round(v_amount, 2);
  v_sst_on := coalesce((payload->>'sstEnabled')::boolean, false);
  v_sst := case when v_sst_on then round(v_amount * 0.06, 2) else 0 end;
  v_total := round(v_amount + v_sst, 2);
  v_desc := coalesce(nullif(payload->>'description',''), 'Engagement ' || v_eng.ref || ' — ' || v_services);

  if coalesce(payload->>'id','') <> '' then
    select * into v_ex from trn_invoices where id = (payload->>'id')::uuid;
    if not found then raise exception 'Invoice not found.'; end if;
    v_id := v_ex.id;
    update trn_invoices set
      inv_no = trim(payload->>'invNo'), engagement_id = v_eng.id, engagement_ref = v_eng.ref,
      client_id = v_eng.client_id, client_company = v_eng.client_company,
      inv_date = payload->>'invDate', due_date = coalesce(payload->>'dueDate',''),
      description = v_desc, amount = v_amount, sst_enabled = v_sst_on, sst_amount = v_sst, total = v_total,
      status = case when payload->>'status' = 'Void' then 'Void' else '' end,
      file_path = coalesce(nullif(payload->>'filePath',''), file_path),
      notes = coalesce(payload->>'notes',''), updated_at = now()
    where id = v_id;
    update trn_jobs set invoice_id = null where invoice_id = v_id;   -- re-stamp
    perform log_audit('UPDATE Invoice', (payload->>'invNo') || ' · ' || v_eng.client_company || ' / RM' || v_total);
  else
    insert into trn_invoices (inv_no, engagement_id, engagement_ref, client_id, client_company,
      inv_date, due_date, description, amount, sst_enabled, sst_amount, total, status, file_path, notes,
      created_by)
    values (trim(payload->>'invNo'), v_eng.id, v_eng.ref, v_eng.client_id, v_eng.client_company,
      payload->>'invDate', coalesce(payload->>'dueDate',''), v_desc,
      v_amount, v_sst_on, v_sst, v_total,
      case when payload->>'status' = 'Void' then 'Void' else '' end,
      coalesce(payload->>'filePath',''), coalesce(payload->>'notes',''), current_email())
    returning id into v_id;
    perform log_audit('CREATE Invoice', (payload->>'invNo') || ' · ' || v_eng.client_company || ' / RM' || v_total);
  end if;

  update trn_jobs set invoice_id = v_id where id = any(v_ids);
  return v_id;
end;
$$;

-- ─── 9 · ALARMS VIEW (read by daily-alarms Edge Function + shown in the UI) ─
-- Same alerts the Apps Script daily email sent: rorobin overstays + overdue invoices.
drop view if exists trn_alarms;
create view trn_alarms with (security_invoker = true) as
select 'BIN_OVERSTAY'::text as alarm_type,
       coalesce(j.engagement_ref,'') || '/Bin ' || coalesce(j.bin_no,'?') as ref,
       'OVERSTAY — Bin ' || coalesce(j.bin_no,'?') || ' · ' || coalesce(j.client_company,'') ||
         ', placed ' || j.place_datetime || ', collect by ' || to_char(j.deadline, 'YYYY-MM-DD HH24:MI') as detail,
       j.deadline::date as due_date,
       coalesce((select nullif(value,'') from trn_settings where key = 'REMINDER_TO'), '') as recipient
from (
  select b.*,
    case when b.placement_type in ('Mall','Office Tower')
      then date_trunc('day', to_timestamp(b.place_datetime, 'YYYY-MM-DD HH24:MI')) + interval '1 day 6 hours'
      else to_timestamp(b.place_datetime, 'YYYY-MM-DD HH24:MI')
           + make_interval(days => greatest(1, coalesce(nullif(b.max_days, 0),
               (select nullif(value,'')::numeric from trn_settings where key = 'ROROBIN_MAX_DAYS'), 3))::int)
    end as deadline
  from trn_jobs b
  where b.service = 'Rorobin'
    and coalesce(b.place_datetime,'') <> ''
    and coalesce(b.collect_datetime,'') = ''
    and b.status not in ('Completed','Cancelled')
) j
where (now() at time zone 'Asia/Kuala_Lumpur') > j.deadline
union all
select 'INVOICE_OVERDUE',
       i.inv_no,
       'OVERDUE invoice ' || i.inv_no || ' · ' || coalesce(i.client_company,'') ||
         ' — balance RM ' || round(i.total - coalesce(p.paid, 0), 2),
       i.due_date::date,
       coalesce((select nullif(value,'') from trn_settings where key = 'REMINDER_TO'), '')
from trn_invoices i
left join (select invoice_id, sum(amount) as paid from trn_payments group by invoice_id) p
       on p.invoice_id = i.id
where coalesce(i.status,'') <> 'Void'
  and coalesce(i.due_date,'') <> ''
  and i.due_date::date < (now() at time zone 'Asia/Kuala_Lumpur')::date
  and (i.total - coalesce(p.paid, 0)) > 0.005;

-- ─── 10 · STORAGE (job photos, invoice files, tipping receipts) ─────────────
insert into storage.buckets (id, name, public) values ('transport-photos','transport-photos', false)
on conflict (id) do nothing;
drop policy if exists "transport-photos_rw" on storage.objects;
create policy "transport-photos_rw" on storage.objects for all to authenticated
  using (bucket_id = 'transport-photos' and is_allowed())
  with check (bucket_id = 'transport-photos' and is_allowed());

-- ─── 11 · ROW-LEVEL SECURITY (allowlist-gated everything) ───────────────────
do $$
declare t text;
begin
  foreach t in array array['trn_clients','trn_engagements','trn_jobs','trn_bins','trn_rates',
                           'trn_workers','trn_lorries','trn_trips','trn_invoices','trn_payments',
                           'trn_photos','trn_settings'] loop
    execute format('alter table %I enable row level security', t);
    execute format('drop policy if exists %I_rw on %I', t, t);
    execute format('create policy %I_rw on %I for all to authenticated using (is_allowed()) with check (is_allowed())', t, t);
  end loop;
end $$;

-- Done. Open transport-supabase.html, connect once, sign in with Google.

-- ========== MODULE: schema-subcon-invoice ==========
-- ============================================================================
-- HG GROUP — SUBCON INVOICE GENERATOR · Supabase schema (prefix: sci_)
-- Run AFTER the foundation schema (supabase/schema.sql).
-- Additive & idempotent — safe to re-run.
--
-- Converted from apps-script-subcon-invoice (Google Sheet: Invoices,
-- InvoiceLines, Subcons, AuditLog + Drive PDFs & Logos).
--   Invoices     → sci_invoices
--   InvoiceLines → sci_invoice_lines
--   Subcons      → sci_subcons (logo file → 'subcon-invoices' storage bucket)
--   AuditLog     → foundation audit_log via log_audit()
--   MY_COMPANY script property → app_settings keys SCI_MY_COMPANY_NAME / _ADDR
--   PDF          → generated client-side via print window (browser Save as PDF);
--                  the record + lines stay authoritative in the database.
-- ============================================================================

-- ─── 1 · INVOICES ───────────────────────────────────────────────────────────
create table if not exists sci_invoices (
  id           uuid primary key default gen_random_uuid(),
  inv_no       text not null unique,
  inv_date     date not null default (now() at time zone 'Asia/Kuala_Lumpur')::date,
  ref          text default '',                -- claim ref / period
  issuer_type  text not null default 'ind',    -- 'ind' (individual) / 'co' (company)
  issuer_name  text not null,
  issuer_ic    text default '',
  issuer_addr  text default '',
  issuer_phone text default '',
  issuer_email text default '',
  bill_to_name text default '',
  bill_to_addr text default '',
  subtotal     numeric not null default 0,
  sst_enabled  boolean not null default false,
  sst_amount   numeric not null default 0,
  total        numeric not null default 0,
  pay_info     text default '',
  notes        text default '',
  created_by   text default '',
  created_at   timestamptz default now()
);

create table if not exists sci_invoice_lines (
  id          uuid primary key default gen_random_uuid(),
  invoice_id  uuid not null references sci_invoices(id) on delete cascade,
  description text default '',
  quantity    numeric default 0,
  unit_price  numeric default 0,
  line_amount numeric default 0,
  sort        int default 1
);
create index if not exists idx_sci_lines_invoice on sci_invoice_lines (invoice_id);

-- ─── 2 · SAVED SUBCONS (remembered issuers, one logo each) ──────────────────
create table if not exists sci_subcons (
  id         uuid primary key default gen_random_uuid(),
  type       text not null default 'ind',      -- 'ind' / 'co'
  name       text not null,
  ic         text default '',
  addr       text default '',
  phone      text default '',
  email      text default '',
  pay_info   text default '',
  logo_path  text default '',                  -- storage path in 'subcon-invoices' bucket
  updated_at timestamptz default now()
);
-- same identity rule as the Apps Script version: unique on (type, name), case-insensitive
create unique index if not exists idx_sci_subcons_key on sci_subcons (type, lower(name));

-- ─── 3 · MY-COMPANY DEFAULT (was Script Property MY_COMPANY) ────────────────
insert into app_settings (key, value) values
  ('SCI_MY_COMPANY_NAME', ''),
  ('SCI_MY_COMPANY_ADDR', '')
on conflict (key) do nothing;

-- ─── 4 · STORAGE BUCKET (subcon logos; replaces Drive "Logos" folder) ───────
insert into storage.buckets (id, name, public) values ('subcon-invoices','subcon-invoices', false)
on conflict (id) do nothing;
drop policy if exists "subcon-invoices_rw" on storage.objects;
create policy "subcon-invoices_rw" on storage.objects for all to authenticated
  using (bucket_id = 'subcon-invoices' and is_allowed())
  with check (bucket_id = 'subcon-invoices' and is_allowed());

-- ─── 5 · SAVE INVOICE RPC — server-side recompute + atomic SUB-YYYY-#### ────
-- payload: { invNo, invDate, ref, issuerType, issuerName, issuerIc, issuerAddr,
--            issuerPhone, issuerEmail, billToName, billToAddr, sstEnabled,
--            payInfo, notes, logoPath,
--            lines: [{description, quantity, unitPrice}] }
-- Mirrors GAS saveInvoice(): recomputes every line (never trusts client maths),
-- SST fixed at 6% when enabled, upserts the subcon, persists the bill-to
-- company default, logs invoice.create.
create or replace function sci_save_invoice(payload jsonb) returns jsonb
language plpgsql security definer set search_path = public as $$
declare
  v_line     jsonb;
  v_qty      numeric; v_unit numeric; v_amt numeric;
  v_subtotal numeric := 0;
  v_sst_on   boolean := coalesce((payload->>'sstEnabled')::boolean, false);
  v_sst      numeric; v_total numeric;
  v_type     text := case when payload->>'issuerType' = 'co' then 'co' else 'ind' end;
  v_name     text := trim(coalesce(payload->>'issuerName',''));
  v_invno    text := trim(coalesce(payload->>'invNo',''));
  v_year     text := to_char(now() at time zone 'Asia/Kuala_Lumpur', 'YYYY');
  v_next     int;
  v_id       uuid;
  v_sub_id   uuid;
  v_logo     text := trim(coalesce(payload->>'logoPath',''));
  v_sort     int := 0;
  v_computed jsonb := '[]'::jsonb;
  v_bt_name  text := trim(coalesce(payload->>'billToName',''));
  v_bt_addr  text := trim(coalesce(payload->>'billToAddr',''));
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  if v_name = '' then raise exception 'Issuer name is required.'; end if;
  if jsonb_array_length(coalesce(payload->'lines','[]'::jsonb)) = 0 then
    raise exception 'At least one line item is required.';
  end if;

  -- serialise number generation (replaces GAS LockService)
  perform pg_advisory_xact_lock(hashtext('sci_invoices'));

  -- recompute lines server-side; drop fully-empty rows (same filter as GAS)
  for v_line in select * from jsonb_array_elements(payload->'lines') loop
    v_qty  := coalesce((v_line->>'quantity')::numeric, 0);
    v_unit := coalesce((v_line->>'unitPrice')::numeric, 0);
    if trim(coalesce(v_line->>'description','')) = '' and v_unit = 0 and v_qty = 0 then
      continue;
    end if;
    v_amt := round(v_qty * v_unit, 2);
    v_subtotal := v_subtotal + v_amt;
    v_sort := v_sort + 1;
    v_computed := v_computed || jsonb_build_object(
      'description', trim(coalesce(v_line->>'description','')),
      'quantity', v_qty, 'unitPrice', v_unit, 'lineAmount', v_amt, 'sort', v_sort);
  end loop;
  if v_sort = 0 then raise exception 'At least one line item with an amount is required.'; end if;

  v_subtotal := round(v_subtotal, 2);
  v_sst      := case when v_sst_on then round(v_subtotal * 0.06, 2) else 0 end;
  v_total    := round(v_subtotal + v_sst, 2);

  -- invoice number: keep a typed one, else next SUB-YYYY-#### for this year
  if v_invno = '' then
    select coalesce(max((regexp_match(inv_no, '^SUB-' || v_year || '-(\d+)$'))[1]::int), 0) + 1
      into v_next
      from sci_invoices
     where inv_no ~ ('^SUB-' || v_year || '-\d+$');
    v_invno := 'SUB-' || v_year || '-' || lpad(v_next::text, 4, '0');
  end if;

  -- remember / update the subcon (same (type, name) identity as GAS upsertSubcon_)
  select id into v_sub_id from sci_subcons
   where type = v_type and lower(name) = lower(v_name);
  if v_sub_id is null then
    insert into sci_subcons (type, name, ic, addr, phone, email, pay_info, logo_path)
    values (v_type, v_name,
            trim(coalesce(payload->>'issuerIc','')),  trim(coalesce(payload->>'issuerAddr','')),
            trim(coalesce(payload->>'issuerPhone','')), trim(coalesce(payload->>'issuerEmail','')),
            coalesce(payload->>'payInfo',''), v_logo)
    returning id into v_sub_id;
  else
    update sci_subcons set
      ic        = trim(coalesce(payload->>'issuerIc','')),
      addr      = trim(coalesce(payload->>'issuerAddr','')),
      phone     = trim(coalesce(payload->>'issuerPhone','')),
      email     = trim(coalesce(payload->>'issuerEmail','')),
      pay_info  = coalesce(payload->>'payInfo',''),
      logo_path = case when v_logo <> '' then v_logo else logo_path end,
      updated_at = now()
    where id = v_sub_id;
  end if;

  -- persist "Bill to" company default for next time (was Script Property)
  if v_bt_name <> '' or v_bt_addr <> '' then
    insert into app_settings (key, value) values
      ('SCI_MY_COMPANY_NAME', v_bt_name), ('SCI_MY_COMPANY_ADDR', v_bt_addr)
    on conflict (key) do update set value = excluded.value;
  end if;

  insert into sci_invoices (inv_no, inv_date, ref, issuer_type, issuer_name, issuer_ic,
      issuer_addr, issuer_phone, issuer_email, bill_to_name, bill_to_addr,
      subtotal, sst_enabled, sst_amount, total, pay_info, notes, created_by)
  values (v_invno,
      coalesce(nullif(trim(coalesce(payload->>'invDate','')),'')::date,
               (now() at time zone 'Asia/Kuala_Lumpur')::date),
      trim(coalesce(payload->>'ref','')), v_type, v_name,
      trim(coalesce(payload->>'issuerIc','')),  trim(coalesce(payload->>'issuerAddr','')),
      trim(coalesce(payload->>'issuerPhone','')), trim(coalesce(payload->>'issuerEmail','')),
      v_bt_name, v_bt_addr,
      v_subtotal, v_sst_on, v_sst, v_total,
      coalesce(payload->>'payInfo',''), coalesce(payload->>'notes',''), current_email())
  returning id into v_id;

  insert into sci_invoice_lines (invoice_id, description, quantity, unit_price, line_amount, sort)
  select v_id, l->>'description', (l->>'quantity')::numeric, (l->>'unitPrice')::numeric,
         (l->>'lineAmount')::numeric, (l->>'sort')::int
  from jsonb_array_elements(v_computed) as l;

  perform log_audit('invoice.create',
    v_invno || ' · ' || v_name || ' · RM ' || to_char(v_total, 'FM999999990.00') ||
    ' · ' || v_sort || ' line(s)');

  return jsonb_build_object('id', v_id, 'invNo', v_invno,
    'subtotal', v_subtotal, 'sstAmount', v_sst, 'total', v_total);
end;
$$;

-- ─── 6 · ROW-LEVEL SECURITY — allowlist-gated ───────────────────────────────
alter table sci_invoices      enable row level security;
alter table sci_invoice_lines enable row level security;
alter table sci_subcons       enable row level security;

drop policy if exists sci_invoices_rw on sci_invoices;
create policy sci_invoices_rw on sci_invoices for all to authenticated
  using (is_allowed()) with check (is_allowed());

drop policy if exists sci_invoice_lines_rw on sci_invoice_lines;
create policy sci_invoice_lines_rw on sci_invoice_lines for all to authenticated
  using (is_allowed()) with check (is_allowed());

drop policy if exists sci_subcons_rw on sci_subcons;
create policy sci_subcons_rw on sci_subcons for all to authenticated
  using (is_allowed()) with check (is_allowed());

-- Done. Open subcon-invoice-supabase.html and connect.

-- ========== MODULE: schema-claims ==========
-- ============================================================================
-- HG GROUP — RECEIPT CLAIMS (clm_) · Supabase schema
-- Run AFTER the foundation schema (supabase/schema.sql).
-- Additive & idempotent — safe to re-run.
--
-- Converted from apps-script-claims (Google Sheet tabs: Claims, ClaimLines,
-- Summaries, AuditLog → foundation audit_log). Drive → storage bucket
-- 'claim-receipts'. Gemini OCR → 'gemini-receipt' Edge Function (frontend).
-- ============================================================================

-- ─── 1 · CLAIMS ─────────────────────────────────────────────────────────────
create table if not exists clm_claims (
  id                  uuid primary key default gen_random_uuid(),
  claim_no            text not null unique,                 -- CLM-YYYY-###
  submitted_at        timestamptz default now(),
  submitted_by        text default '',
  receipt_date        date not null default (now() at time zone 'Asia/Kuala_Lumpur')::date,
  vendor              text not null default 'Unknown vendor',
  currency            text not null default 'RM',
  subtotal            numeric not null default 0,
  service_charge      numeric not null default 0,           -- restaurant SC (RM)
  subsidy_amount      numeric not null default 0,           -- Budi95 / fuel subsidy deducted
  sst_amount          numeric not null default 0,
  rounding_adjustment numeric not null default 0,           -- signed 5-sen cash rounding
  total               numeric not null default 0,           -- net claimable
  primary_category    text not null default 'other',
  status              text not null default 'submitted',
  receipt_paths       jsonb not null default '[]'::jsonb,   -- storage paths in 'claim-receipts'
  remarks             text default '',
  created_by          text default '',
  created_at          timestamptz default now()
);
create index if not exists idx_clm_claims_by on clm_claims (submitted_by);
create index if not exists idx_clm_claims_no on clm_claims (claim_no);

-- ─── 2 · CLAIM LINES ────────────────────────────────────────────────────────
create table if not exists clm_claim_lines (
  id          uuid primary key default gen_random_uuid(),
  claim_id    uuid not null references clm_claims(id) on delete cascade,
  description text not null default '',
  quantity    numeric not null default 0,
  unit_price  numeric not null default 0,
  line_amount numeric not null default 0,
  category    text not null default 'other',
  remarks     text default '',
  sort        int default 1
);
create index if not exists idx_clm_lines_claim on clm_claim_lines (claim_id);

-- ─── 3 · SUMMARIES (bundles of claims) ──────────────────────────────────────
create table if not exists clm_summaries (
  id           uuid primary key default gen_random_uuid(),
  summary_no   text not null unique,                        -- SUM-YYYY-###
  generated_at timestamptz default now(),
  generated_by text default '',
  claim_nos    text not null default '',                    -- 'CLM-2026-001 | CLM-2026-002'
  claim_count  int not null default 0,
  currency     text not null default 'RM',
  grand_total  numeric not null default 0,
  period_from  date,
  period_to    date,
  title        text default '',
  remarks      text default '',
  created_by   text default '',
  created_at   timestamptz default now()
);
create index if not exists idx_clm_summaries_by on clm_summaries (generated_by);

-- ─── 4 · SST rate setting (reuses foundation app_settings; seed if missing) ─
insert into app_settings (key, value) values ('SST_PERCENT', '6')
on conflict (key) do nothing;

-- ─── 5 · SUBMIT CLAIM RPC — server-side recompute + atomic claim number ─────
-- payload: { vendor, receiptDate, currency, sstEnabled, serviceCharge,
--            subsidyAmount, roundingAdjustment, remarks, receiptPaths:[...],
--            lines: [{description, quantity, unitPrice, category, remarks}] }
-- Mirrors submitClaimCore_ in apps-script-claims/Code.gs — never trusts client maths.
create or replace function clm_submit_claim(payload jsonb) returns jsonb
language plpgsql security definer set search_path = public as $$
declare
  v_line     jsonb;
  v_qty      numeric; v_unit numeric; v_amt numeric;
  v_subtotal numeric := 0;
  v_sc       numeric; v_subsidy numeric; v_round numeric;
  v_sstpct   numeric := 6;
  v_sst      numeric := 0; v_taxbase numeric; v_total numeric;
  v_cat      text;
  v_year     text := to_char(now() at time zone 'Asia/Kuala_Lumpur', 'YYYY');
  v_next     int;
  v_no       text;
  v_id       uuid;
  v_sort     int := 0;
  v_computed jsonb := '[]'::jsonb;
  v_primary  text;
  v_vendor   text; v_currency text; v_date date;
  v_cats     text[] := array['food','grocery','apparel','fuel','transport',
                             'accommodation','materials','tools','office','other'];
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  if jsonb_array_length(coalesce(payload->'lines', '[]'::jsonb)) = 0 then
    raise exception 'At least one line item required.';
  end if;
  if jsonb_array_length(coalesce(payload->'receiptPaths', '[]'::jsonb)) = 0 then
    raise exception 'At least one receipt image required.';
  end if;

  -- recompute every line (qty × unit price) — same rules as the GAS server
  for v_line in select * from jsonb_array_elements(payload->'lines') loop
    v_qty  := coalesce((v_line->>'quantity')::numeric, 0);
    v_unit := coalesce((v_line->>'unitPrice')::numeric, 0);
    v_amt  := round(v_qty * v_unit, 2);
    v_cat  := lower(coalesce(v_line->>'category', 'other'));
    if not (v_cat = any(v_cats)) then v_cat := 'other'; end if;
    v_subtotal := v_subtotal + v_amt;
    v_sort := v_sort + 1;
    v_computed := v_computed || jsonb_build_object(
      'description', trim(coalesce(v_line->>'description','')),
      'quantity', v_qty, 'unitPrice', v_unit, 'lineAmount', v_amt,
      'category', v_cat, 'remarks', coalesce(v_line->>'remarks',''), 'sort', v_sort);
  end loop;
  v_subtotal := round(v_subtotal, 2);

  v_sc      := greatest(0, round(coalesce((payload->>'serviceCharge')::numeric, 0), 2));
  v_subsidy := greatest(0, round(coalesce((payload->>'subsidyAmount')::numeric, 0), 2));
  v_round   := round(coalesce((payload->>'roundingAdjustment')::numeric, 0), 2);
  v_taxbase := greatest(0, v_subtotal + v_sc - v_subsidy);
  if coalesce((payload->>'sstEnabled')::boolean, false) then
    select coalesce(nullif(value,'')::numeric, 6) into v_sstpct
    from app_settings where key = 'SST_PERCENT';
    v_sstpct := coalesce(v_sstpct, 6);
    v_sst := round(v_taxbase * v_sstpct / 100, 2);
  end if;
  v_total := round(v_subtotal + v_sc - v_subsidy + v_sst + v_round, 2);

  -- primary category = category covering the largest share of the total
  select l.cat into v_primary from (
    select x->>'category' as cat, sum((x->>'lineAmount')::numeric) as s
    from jsonb_array_elements(v_computed) x group by 1 order by s desc limit 1
  ) l;
  v_primary := coalesce(v_primary, 'other');

  v_vendor   := coalesce(nullif(trim(payload->>'vendor'), ''), 'Unknown vendor');
  v_currency := coalesce(nullif(trim(payload->>'currency'), ''), 'RM');
  v_date     := coalesce(nullif(payload->>'receiptDate','')::date,
                         (now() at time zone 'Asia/Kuala_Lumpur')::date);

  -- atomic sequential claim number: CLM-YYYY-###
  select coalesce(max((substring(claim_no from 10))::int), 0) + 1 into v_next
  from clm_claims
  where claim_no like 'CLM-' || v_year || '-%'
    and substring(claim_no from 10) ~ '^[0-9]+$';
  v_no := 'CLM-' || v_year || '-' || lpad(v_next::text, 3, '0');

  insert into clm_claims (claim_no, submitted_by, receipt_date, vendor, currency,
                          subtotal, service_charge, subsidy_amount, sst_amount,
                          rounding_adjustment, total, primary_category, status,
                          receipt_paths, remarks, created_by)
  values (v_no, current_email(), v_date, v_vendor, v_currency,
          v_subtotal, v_sc, v_subsidy, v_sst,
          v_round, v_total, v_primary, 'submitted',
          coalesce(payload->'receiptPaths', '[]'::jsonb),
          coalesce(payload->>'remarks',''), current_email())
  returning id into v_id;

  insert into clm_claim_lines (claim_id, description, quantity, unit_price,
                               line_amount, category, remarks, sort)
  select v_id, l->>'description', (l->>'quantity')::numeric, (l->>'unitPrice')::numeric,
         (l->>'lineAmount')::numeric, l->>'category', l->>'remarks', (l->>'sort')::int
  from jsonb_array_elements(v_computed) as l;

  perform log_audit('claim.create',
    v_no || ' · ' || v_vendor || ' · ' || v_currency || ' ' || to_char(v_total, 'FM999999990.00')
    || ' · ' || jsonb_array_length(v_computed) || ' line(s)');

  return jsonb_build_object(
    'id', v_id, 'claimNo', v_no, 'vendor', v_vendor, 'currency', v_currency,
    'subtotal', v_subtotal, 'serviceCharge', v_sc, 'subsidyAmount', v_subsidy,
    'sstAmount', v_sst, 'roundingAdjustment', v_round, 'total', v_total,
    'primaryCategory', v_primary, 'receiptDate', v_date);
end;
$$;

-- ─── 6 · GENERATE SUMMARY RPC — bundle N claims, atomic SUM-YYYY-### ────────
-- payload: { claimNos: ['CLM-2026-001', ...], title?, remarks? }
-- Mirrors generateSummary in Code.gs. Staff can only bundle their own claims.
create or replace function clm_generate_summary(payload jsonb) returns jsonb
language plpgsql security definer set search_path = public as $$
declare
  v_nos      text[];
  v_missing  text[];
  v_count    int;
  v_grand    numeric;
  v_currency text;
  v_from     date; v_to date;
  v_year     text := to_char(now() at time zone 'Asia/Kuala_Lumpur', 'YYYY');
  v_next     int;
  v_no       text;
  v_id       uuid;
begin
  if not is_allowed() then raise exception 'Not authorised.'; end if;
  select array_agg(x) into v_nos
  from jsonb_array_elements_text(coalesce(payload->'claimNos','[]'::jsonb)) as x;
  if v_nos is null or array_length(v_nos, 1) = 0 then
    raise exception 'Pick at least one claim to summarise.';
  end if;

  -- claims visible to this user only (admin sees all)
  select count(*), round(coalesce(sum(total), 0), 2),
         min(receipt_date), max(receipt_date)
    into v_count, v_grand, v_from, v_to
  from clm_claims
  where claim_no = any(v_nos)
    and (is_admin() or lower(submitted_by) = lower(current_email()));

  if v_count = 0 then raise exception 'None of the selected claims were found.'; end if;

  select array_agg(n) into v_missing
  from unnest(v_nos) as n
  where not exists (
    select 1 from clm_claims c where c.claim_no = n
      and (is_admin() or lower(c.submitted_by) = lower(current_email())));
  if v_missing is not null then
    raise exception 'Not found: %', array_to_string(v_missing, ', ');
  end if;

  -- primary currency = the one carrying the largest share of the total
  select currency into v_currency from (
    select currency, sum(total) as s from clm_claims
    where claim_no = any(v_nos)
      and (is_admin() or lower(submitted_by) = lower(current_email()))
    group by currency order by s desc limit 1
  ) c;
  v_currency := coalesce(v_currency, 'RM');

  -- atomic sequential summary number: SUM-YYYY-###
  select coalesce(max((substring(summary_no from 10))::int), 0) + 1 into v_next
  from clm_summaries
  where summary_no like 'SUM-' || v_year || '-%'
    and substring(summary_no from 10) ~ '^[0-9]+$';
  v_no := 'SUM-' || v_year || '-' || lpad(v_next::text, 3, '0');

  insert into clm_summaries (summary_no, generated_by, claim_nos, claim_count,
                             currency, grand_total, period_from, period_to,
                             title, remarks, created_by)
  values (v_no, current_email(), array_to_string(v_nos, ' | '), v_count,
          v_currency, v_grand, v_from, v_to,
          coalesce(trim(payload->>'title'),''), coalesce(trim(payload->>'remarks'),''),
          current_email())
  returning id into v_id;

  perform log_audit('summary.create',
    v_no || ' · ' || v_count || ' claim(s) · ' || v_currency || ' '
    || to_char(v_grand, 'FM999999990.00'));

  return jsonb_build_object(
    'id', v_id, 'summaryNo', v_no, 'claimCount', v_count, 'currency', v_currency,
    'grandTotal', v_grand, 'periodFrom', v_from, 'periodTo', v_to,
    'title', coalesce(trim(payload->>'title'),''));
end;
$$;

-- ─── 7 · STORAGE — receipt photos (replaces Drive "Black Lee — Claims") ─────
insert into storage.buckets (id, name, public) values ('claim-receipts','claim-receipts', false)
on conflict (id) do nothing;
drop policy if exists "claim-receipts_rw" on storage.objects;
create policy "claim-receipts_rw" on storage.objects for all to authenticated
  using (bucket_id = 'claim-receipts' and is_allowed())
  with check (bucket_id = 'claim-receipts' and is_allowed());

-- ─── 8 · ROW-LEVEL SECURITY — per-user privacy (staff own rows, admin all) ──
alter table clm_claims      enable row level security;
alter table clm_claim_lines enable row level security;
alter table clm_summaries   enable row level security;

drop policy if exists clm_claims_rw on clm_claims;
create policy clm_claims_rw on clm_claims for all to authenticated
  using (is_allowed() and (is_admin() or lower(submitted_by) = lower(current_email())))
  with check (is_allowed() and (is_admin() or lower(submitted_by) = lower(current_email())));

drop policy if exists clm_claim_lines_rw on clm_claim_lines;
create policy clm_claim_lines_rw on clm_claim_lines for all to authenticated
  using (is_allowed() and exists (
    select 1 from clm_claims c where c.id = claim_id
      and (is_admin() or lower(c.submitted_by) = lower(current_email()))))
  with check (is_allowed() and exists (
    select 1 from clm_claims c where c.id = claim_id
      and (is_admin() or lower(c.submitted_by) = lower(current_email()))));

drop policy if exists clm_summaries_rw on clm_summaries;
create policy clm_summaries_rw on clm_summaries for all to authenticated
  using (is_allowed() and (is_admin() or lower(generated_by) = lower(current_email())))
  with check (is_allowed() and (is_admin() or lower(generated_by) = lower(current_email())));

-- Done. Frontend: claims-supabase.html · OCR: 'gemini-receipt' Edge Function.

-- ========== MODULE: schema-expenses ==========
-- ============================================================================
-- HG GROUP — EXPENSES RECEIPT SYSTEM · Supabase schema  (prefix: exp_)
-- Converted from apps-script-expenses (Google Apps Script + bound Sheet).
-- Run AFTER the foundation schema (supabase/schema.sql). Safe to re-run:
-- everything is IF NOT EXISTS / ON CONFLICT DO NOTHING / CREATE OR REPLACE.
--
-- What it creates:
--   1. exp_categories          — admin-editable category list ('other' = locked fallback)
--   2. exp_expenses            — one row per receipt (per-user private via RLS)
--   3. category RPCs           — exp_add_category / exp_rename_category / exp_delete_category
--                                (atomic: rename/delete re-tags existing receipts)
--   4. expense-receipts bucket — private storage for receipt images/PDFs,
--                                one folder per user email (private per user, admin sees all)
--   5. RLS                     — staff see ONLY their own rows; admin sees everyone's
--
-- Uses (never redefines) from the foundation: allowed_users, is_allowed(),
-- is_admin(), current_email(), log_audit().
-- ============================================================================

-- ─── 1 · CATEGORIES (was Script Properties CATEGORIES_JSON) ─────────────────
create table if not exists exp_categories (
  name text primary key,
  sort int default 0
);

-- Seed = the GAS CATEGORIES list. 'other' is the locked fallback (sort last).
insert into exp_categories (name, sort) values
  ('food', 1), ('grocery', 2), ('fuel', 3), ('transport', 4),
  ('accommodation', 5), ('parking', 6), ('toll', 7), ('materials', 8),
  ('tools', 9), ('office', 10), ('utilities', 11), ('phone', 12),
  ('other', 999)
on conflict (name) do nothing;

-- ─── 2 · EXPENSES (was the 'Expenses' sheet) ────────────────────────────────
create table if not exists exp_expenses (
  id           uuid primary key default gen_random_uuid(),
  created_at   timestamptz default now(),
  created_by   text default '',                    -- was submittedBy (owner email)
  receipt_date date not null default (now() at time zone 'Asia/Kuala_Lumpur')::date,
  month_key    text default '',                    -- yyyy-MM, kept in sync by trigger
  vendor       text default '',
  description  text default '',
  category     text default 'other',
  currency     text default 'RM',
  amount       numeric default 0,
  type         text default 'business',            -- business / personal
  status       text default 'recorded',
  image_path   text default '',                    -- storage path in expense-receipts bucket
  remarks      text default ''
);
create index if not exists idx_exp_expenses_owner on exp_expenses (created_by);
create index if not exists idx_exp_expenses_month on exp_expenses (month_key);

-- month_key always derived from receipt_date (was monthKeyOf_ in Code.gs)
create or replace function exp_set_month_key() returns trigger
language plpgsql as $$
begin
  new.month_key := to_char(new.receipt_date, 'YYYY-MM');
  return new;
end;
$$;
drop trigger if exists exp_expenses_month_key on exp_expenses;
create trigger exp_expenses_month_key
  before insert or update on exp_expenses
  for each row execute function exp_set_month_key();

-- ─── 3 · CATEGORY RPCs (admin-only, atomic re-tagging like the GAS version) ─
create or replace function exp_add_category(p_name text) returns void
language plpgsql security definer set search_path = public as $$
declare v_name text := lower(trim(regexp_replace(coalesce(p_name,''), '\s+', ' ', 'g')));
begin
  if not is_admin() then raise exception 'Only the admin can manage categories.'; end if;
  if v_name = '' then raise exception 'Enter a category name.'; end if;
  if v_name !~ '^[a-z0-9 &/-]+$' then raise exception 'Use letters, numbers, spaces, & / - only.'; end if;
  if length(v_name) > 24 then raise exception 'Keep it under 24 characters.'; end if;
  if exists (select 1 from exp_categories where name = v_name) then
    raise exception '"%" already exists.', v_name;
  end if;
  insert into exp_categories (name, sort)
  values (v_name, (select coalesce(max(sort), 0) + 1 from exp_categories where sort < 999));
  perform log_audit('EXP category-add', v_name);
end;
$$;

create or replace function exp_rename_category(p_old text, p_new text) returns int
language plpgsql security definer set search_path = public as $$
declare
  v_old text := lower(trim(regexp_replace(coalesce(p_old,''), '\s+', ' ', 'g')));
  v_new text := lower(trim(regexp_replace(coalesce(p_new,''), '\s+', ' ', 'g')));
  v_moved int;
begin
  if not is_admin() then raise exception 'Only the admin can manage categories.'; end if;
  if v_old = '' or v_new = '' then raise exception 'Missing name.'; end if;
  if v_old = 'other' then raise exception '"other" is the fallback category — it cannot be renamed.'; end if;
  if v_new !~ '^[a-z0-9 &/-]+$' then raise exception 'Use letters, numbers, spaces, & / - only.'; end if;
  if length(v_new) > 24 then raise exception 'Keep it under 24 characters.'; end if;
  if not exists (select 1 from exp_categories where name = v_old) then
    raise exception '"%" not found.', v_old;
  end if;
  if v_old <> v_new and exists (select 1 from exp_categories where name = v_new) then
    raise exception '"%" already exists.', v_new;
  end if;
  update exp_categories set name = v_new where name = v_old;
  update exp_expenses set category = v_new where category = v_old;   -- keep receipts consistent
  get diagnostics v_moved = row_count;
  perform log_audit('EXP category-rename', v_old || ' -> ' || v_new || ' (' || v_moved || ' rows)');
  return v_moved;
end;
$$;

create or replace function exp_delete_category(p_name text) returns int
language plpgsql security definer set search_path = public as $$
declare
  v_name text := lower(trim(regexp_replace(coalesce(p_name,''), '\s+', ' ', 'g')));
  v_moved int;
begin
  if not is_admin() then raise exception 'Only the admin can manage categories.'; end if;
  if v_name = 'other' then raise exception '"other" cannot be deleted — it is the fallback.'; end if;
  if not exists (select 1 from exp_categories where name = v_name) then
    raise exception '"%" not found.', v_name;
  end if;
  delete from exp_categories where name = v_name;
  update exp_expenses set category = 'other' where category = v_name;  -- affected receipts -> other
  get diagnostics v_moved = row_count;
  perform log_audit('EXP category-delete', v_name || ' (' || v_moved || ' rows -> other)');
  return v_moved;
end;
$$;

-- ─── 4 · STORAGE — receipt images (was Google Drive per-user folders) ───────
insert into storage.buckets (id, name, public) values ('expense-receipts','expense-receipts', false)
on conflict (id) do nothing;

-- Private per user, like the Drive per-person subfolders: each user may only
-- touch objects under their own email folder; admin may touch everything.
drop policy if exists "expense-receipts_rw" on storage.objects;
create policy "expense-receipts_rw" on storage.objects for all to authenticated
  using (bucket_id = 'expense-receipts' and is_allowed()
         and (is_admin() or (storage.foldername(name))[1] = current_email()))
  with check (bucket_id = 'expense-receipts' and is_allowed()
              and (is_admin() or (storage.foldername(name))[1] = current_email()));

-- ─── 5 · ROW-LEVEL SECURITY ─────────────────────────────────────────────────
-- Per-user privacy exactly like the GAS version: staff see only their own
-- receipts; admin sees everyone's. Enforced by the database, not the screen.
alter table exp_expenses enable row level security;
drop policy if exists exp_expenses_rw on exp_expenses;
create policy exp_expenses_rw on exp_expenses for all to authenticated
  using (is_allowed() and (is_admin() or created_by = current_email()))
  with check (is_allowed() and (is_admin() or created_by = current_email()));

-- Categories: everyone allowlisted may read (dropdowns); writes only via the
-- admin-guarded security definer RPCs above.
alter table exp_categories enable row level security;
drop policy if exists exp_categories_read on exp_categories;
create policy exp_categories_read on exp_categories for select to authenticated
  using (is_allowed());

-- Done. Frontend: expenses-supabase.html · AI reading: 'gemini-receipt' Edge Function.

-- ========== MODULE: schema-mall-platform ==========
-- ============================================================================
-- HG MALL PLATFORM — Supabase schema (prefix mp_)
-- Run AFTER the foundation schema (supabase/schema.sql).
-- Additive + idempotent: safe to re-run. Uses foundation helpers:
--   is_allowed(), is_admin(), current_email(), log_audit(), allowed_users, audit_log
--
-- Converted from mall-platform/Code.gs:
--   Door 1  Site Drawing Vault  (Drive → storage bucket 'mall-sketches',
--           auto-versioning v1, v2, v3… per Mall+Lot preserved via mp_next_version)
--   Door 2  Requirement Lookup + Panel rate book (all reference tables)
--   Door 3  HIRARC / MOS generator (SWMS templates)
--   Door 4  Measurement Request tracker
-- ============================================================================

-- ─── 1 · TABLES ──────────────────────────────────────────────────────────────

-- Malls master (app-local; the GAS app had its own Malls sheet)
create table if not exists mp_malls (
  id         uuid primary key default gen_random_uuid(),
  name       text not null unique,
  code       text default '',
  location   text default '',
  notes      text default '',
  added_by   text default '',
  created_at timestamptz default now()
);

-- Door 1 — the Sketches log (was the 'Sketches' sheet + Drive files)
create table if not exists mp_sketches (
  id           uuid primary key default gen_random_uuid(),
  mall         text not null,
  code         text default '',
  lot_no       text not null,
  shop_type    text default '',
  version      int not null default 1,
  file_name    text not null,
  storage_path text not null,          -- path inside the 'mall-sketches' bucket
  mime_type    text default '',
  remarks      text default '',
  uploaded_by  text default '',
  created_at   timestamptz default now()
);
create index if not exists idx_mp_sketches_mall_lot on mp_sketches (mall, lot_no);

create table if not exists mp_categories (
  id uuid primary key default gen_random_uuid(),
  name text not null, sort int default 0, created_at timestamptz default now()
);

create table if not exists mp_requirements (
  id          uuid primary key default gen_random_uuid(),
  mall        text not null,
  category    text default '',
  requirement text default '',
  type        text default '',
  value       text default '',
  shop_type   text default '',
  notes       text default '',
  sort        int default 0,
  updated_by  text default '',
  updated_at  timestamptz default now(),
  created_at  timestamptz default now()
);
create index if not exists idx_mp_requirements_mall on mp_requirements (mall);

create table if not exists mp_requirement_types (
  id uuid primary key default gen_random_uuid(),
  category text default '', name text not null, sort int default 0,
  created_at timestamptz default now()
);

-- the Hoarding / Visual "Type" dropdown options (was the 'Types' sheet)
create table if not exists mp_types (
  id uuid primary key default gen_random_uuid(),
  category text default '', name text not null, sort int default 0,
  created_at timestamptz default now()
);

create table if not exists mp_job_categories (
  id uuid primary key default gen_random_uuid(),
